INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Opisz fazy cyklu serca', 'Cykl serca składa się z systole (skurcz) i diastole (rozkurcz). Systole obejmuje fazę skurczu izowolumetrycznego i fazę wyrzutu. Diastole obejmuje fazę rozkurczu izowolumetrycznego, szybkiego napełniania i wolnego napełniania (diastasis). Skurcz przedsionków kończy napełnianie komór.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Franka-Starlinga', 'Siła skurczu mięśnia sercowego jest proporcjonalna do stopnia jego rozciągnięcia w fazie rozkurczu (objętości końcoworozkurczowej). Im większe wypełnienie komory, tym większa objętość wyrzutowa — do pewnej granicy. Mechanizm zapewnia równowagę między rzutem prawej i lewej komory.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Objętość wyrzutowa (SV) — definicja i wartość', 'Objętość wyrzutowa to różnica między objętością końcoworozkurczową (EDV, ~120 ml) a końcowoskurczową (ESV, ~50 ml). Prawidłowa SV wynosi ok. 70 ml. SV = EDV − ESV. Zależy od obciążenia wstępnego, następczego i kurczliwości.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rzut serca (CO) — wzór i wartość prawidłowa', 'Rzut serca (cardiac output) = SV × HR. Prawidłowa wartość to ok. 5 L/min w spoczynku. Indeks sercowy (CI) = CO/BSA, norma 2,5–4,0 L/min/m². CO wzrasta przy wysiłku nawet do 25 L/min u osób zdrowych.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Frakcja wyrzutowa (EF) — definicja i znaczenie kliniczne', 'Frakcja wyrzutowa = SV/EDV × 100%. Prawidłowa EF lewej komory wynosi 55–70%. EF < 40% wskazuje na niewydolność serca ze zmniejszoną frakcją wyrzutową (HFrEF). Jest kluczowym parametrem oceny funkcji skurczowej serca w echokardiografii.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obciążenie wstępne (preload)', 'Obciążenie wstępne to stopień rozciągnięcia kardiomiocytów przed skurczem, odpowiadający objętości końcoworozkurczowej (EDV). Zależy od powrotu żylnego, wolemii i podatności komory. Wzrost preloadu zwiększa SV zgodnie z prawem Franka-Starlinga.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obciążenie następcze (afterload)', 'Obciążenie następcze to opór, który musi pokonać komora podczas wyrzutu krwi. Dla lewej komory jest to głównie opór naczyń systemowych (SVR), dla prawej — opór naczyń płucnych (PVR). Wzrost afterloadu zmniejsza SV i zwiększa zużycie tlenu przez mięsień sercowy.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kurczliwość (inotropia) — co ją moduluje?', 'Kurczliwość to zdolność kardiomiocytów do generowania siły niezależnie od preloadu. Działanie inotropowe dodatnie: katecholaminy, digoksyna, Ca²⁺. Działanie inotropowe ujemne: β-blokery, blokery kanałów wapniowych, kwasica, niedokrwienie. Mechanizm: zmiana stężenia Ca²⁺ wewnątrzkomórkowego.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ bodźcoprzewodzący serca', 'Węzeł zatokowo-przedsionkowy (SA) → szlaki międzywęzłowe → węzeł przedsionkowo-komorowy (AV) → pęczek Hisa → odnogi prawy i lewe → włókna Purkinjego. Węzeł SA jest naturalnym rozrusznikiem (60–100/min). Węzeł AV opóźnia przewodzenie (~0,1 s), chroniąc komory przed zbyt szybkim rytmem.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Potencjał czynnościowy kardiomiocytu roboczego — fazy', 'Faza 0: szybka depolaryzacja (kanały Na⁺). Faza 1: wstępna repolaryzacja (przejściowy prąd K⁺). Faza 2: plateau (prąd Ca²⁺ typu L równoważy prąd K⁺). Faza 3: repolaryzacja (prąd K⁺). Faza 4: spoczynkowy potencjał (~−90 mV). Plateau wydłuża okres refrakcji, chroniąc przed tętnem nawrotnym.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Automatyzm komórek rozrusznikowych (faza 4)', 'Komórki węzła SA i AV nie mają stabilnego potencjału spoczynkowego. Faza 4 to powolna spontaniczna depolaryzacja (prąd funny If — Na⁺/K⁺). Po osiągnięciu progu (~−40 mV) otwierają się kanały Ca²⁺ typu L, generując potencjał czynnościowy. Katecholaminy przyspieszają If, acetylocholina zwalnia.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Załamek P w EKG', 'Załamek P odpowiada depolaryzacji przedsionków. Prawidłowy czas trwania < 120 ms, amplituda < 2,5 mm w odprowadzeniu II. Poszerzenie P wskazuje na powiększenie lewego przedsionka (P mitrale), zwiększona amplituda — prawego (P pulmonale).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zespół QRS w EKG', 'Zespół QRS odpowiada depolaryzacji komór. Prawidłowy czas trwania 60–100 ms. Poszerzenie > 120 ms sugeruje blok odnogi pęczka Hisa lub rytm komorowy. Amplituda koreluje z masą mięśniową komory — przerost LV daje wysokie R w V5-V6.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Załamek T w EKG', 'Załamek T odpowiada repolaryzacji komór. Prawidłowo zgodny z kierunkiem QRS. Odwrócenie T może wskazywać na niedokrwienie, przerost komory lub zaburzenia elektrolitowe. Spiczaste, wysokie T sugerują hiperkaliemię.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odcinek ST — znaczenie kliniczne', 'Odcinek ST łączy koniec QRS z początkiem T. Prawidłowo izoelektryczny. Uniesienie ST ≥ 1 mm sugeruje ostry zawał (STEMI) lub zapalenie osierdzia. Obniżenie ST wskazuje na niedokrwienie podwsierdziowe lub działanie digoksyny.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odstęp PQ (PR) w EKG', 'Odstęp PQ mierzy czas od początku depolaryzacji przedsionków do początku depolaryzacji komór. Norma: 120–200 ms. Wydłużenie > 200 ms = blok AV I stopnia. Skrócenie < 120 ms sugeruje zespół preekscytacji (np. WPW).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odstęp QT — znaczenie i korekta', 'Odstęp QT odpowiada całkowitemu czasowi depolaryzacji i repolaryzacji komór. Korygowany wzorem Bazetta: QTc = QT/√RR. Prawidłowy QTc < 440 ms (mężczyźni), < 460 ms (kobiety). Wydłużenie QTc predysponuje do torsade de pointes.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zastawka mitralna (dwudzielna)', 'Zastawka mitralna leży między lewym przedsionkiem a lewą komorą. Posiada dwa płatki (przedni i tylny), struny ścięgniste i mięśnie brodawkowate. Zamknięcie tworzy I ton serca (S1). Niedomykalność objawia się szmerem skurczowym.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zastawka aortalna', 'Zastawka aortalna ma trzy płatki półksiężycowate (prawy, lewy, tylny). Zamknięcie tworzy komponentę aortalną II tonu (A2). Stenoza aortalna daje szmer skurczowy crescendo-decrescendo. Tuż nad zastawką odchodzą tętnice wieńcowe.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tony serca S1 i S2', 'S1 — zamknięcie zastawek przedsionkowo-komorowych (mitralnej i trójdzielnej) na początku skurczu komór. S2 — zamknięcie zastawek półksiężycowatych (aortalnej i płucnej) na początku rozkurczu. S2 fizjologicznie rozdwaja się na wdechu (opóźnione P2).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tony serca S3 i S4', 'S3 — wczesnorozkurczowy ton spowodowany szybkim napełnianiem rozciągniętej komory. Fizjologiczny u młodych, u starszych sugeruje niewydolność serca. S4 — późnorozkurczowy ton towarzyszący skurczowi przedsionków przy zmniejszonej podatności komory (przerost, kardiomiopatia).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie wieńcowe — zaopatrzenie', 'Lewa tętnica wieńcowa (LCA) dzieli się na gałąź przednią zstępującą (LAD — przegroda, ściana przednia) i okalającą (LCx — ściana boczna). Prawa tętnica wieńcowa (RCA) zaopatruje ścianę dolną i węzeł SA (u ~60% osób). U ~85% dominacja prawostronna (RCA daje gałąź zstępującą tylną).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Autoregulacja przepływu wieńcowego', 'Przepływ wieńcowy jest stały przy ciśnieniu perfuzji 60–140 mmHg dzięki autoregulacji metabolicznej. Główny mediator rozszerzający naczynia wieńcowe to adenozyna (uwalniana przy niedokrwieniu). Przepływ w lewej komorze odbywa się głównie w rozkurczu, gdy ciśnienie wewnątrzsercowe jest niskie.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ciśnienie tętnicze — składowe', 'Ciśnienie skurczowe (SBP) zależy głównie od objętości wyrzutowej i podatności aorty. Ciśnienie rozkurczowe (DBP) zależy od oporu obwodowego i czasu rozkurczu. Ciśnienie tętna (PP) = SBP − DBP. Średnie ciśnienie tętnicze (MAP) ≈ DBP + 1/3 PP. Prawidłowe MAP: 70–105 mmHg.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Średnie ciśnienie tętnicze (MAP) — wzór i znaczenie', 'MAP = CO × SVR. Alternatywnie: MAP ≈ DBP + 1/3(SBP − DBP). MAP > 60 mmHg jest minimum do perfuzji narządów. MAP jest regulowane przez układ współczulny, RAAS, ADH i peptydy natriuretyczne. Jest głównym wyznacznikiem perfuzji tkankowej.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Baroreceptory — lokalizacja i funkcja', 'Baroreceptory tętnicze znajdują się w zatoce szyjnej (n. IX — językowo-gardłowy) i łuku aorty (n. X — błędny). Rejestrują rozciągnięcie ściany naczynia. Wzrost ciśnienia → zwiększenie impulsacji → hamowanie ośrodka naczynioruchowego → bradykardia i wazodylatacja. Odruch działa szybko, ale adaptuje się w ciągu 1–2 dni.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch z baroreceptorów przy nagłym spadku ciśnienia', 'Spadek ciśnienia → zmniejszenie rozciągnięcia baroreceptorów → mniejsza impulsacja do jądra pasma samotnego → aktywacja ośrodka naczynioruchowego → wzrost aktywności współczulnej → tachykardia, wzrost kurczliwości, wazokonstrykcja → przywrócenie ciśnienia.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ renina-angiotensyna-aldosteron (RAAS)', 'Spadek ciśnienia/perfuzji nerki → wydzielanie reniny z aparatu przykłębuszkowego → konwersja angiotensynogenu do angiotensyny I → ACE (płuca) → angiotensyna II. Ang II: wazokonstrykcja, wydzielanie aldosteronu (retencja Na⁺/H₂O), wydzielanie ADH, pragnienie. RAAS reguluje długoterminowo ciśnienie.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Angiotensyna II — działanie', 'Ang II jest silnym wazokonstryktorem (receptor AT1). Stymuluje wydzielanie aldosteronu z kory nadnerczy, ADH z tylnego płata przysadki, pobudza pragnienie. Wywołuje przerost mięśnia sercowego i naczyń. Inhibitory ACE i sartany (ARB) blokują ten szlak w leczeniu nadciśnienia i niewydolności serca.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aldosteron — mechanizm działania', 'Aldosteron działa na komórki cewki zbiorczej nerki. Zwiększa ekspresję kanałów ENaC (resorpcja Na⁺) i kanałów ROMK (wydzielanie K⁺). Efekt: retencja sodu i wody, wydalanie potasu. Nadmiar aldosteronu prowadzi do hipokaliemii i nadciśnienia (zespół Conna).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wazopresyna (ADH) — rola w regulacji ciśnienia', 'ADH jest wydzielana z tylnego płata przysadki w odpowiedzi na wzrost osmolalności lub spadek wolemii. Receptor V2 (cewka zbiorcza) — wbudowanie akwaporyn, retencja wody. Receptor V1 (naczynia) — wazokonstrykcja. W dużych dawkach ADH istotnie podnosi ciśnienie tętnicze.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Peptyd natriuretyczny typu B (BNP)', 'BNP jest wydzielany przez kardiomiocyty komór w odpowiedzi na rozciągnięcie ściany. Powoduje natriurezę, diurezę i wazodylatację oraz hamuje RAAS i współczulny układ nerwowy. NT-proBNP jest markerem niewydolności serca — poziom koreluje z ciężkością choroby.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tlenek azotu (NO) — rola naczyniowa', 'NO jest wytwarzany przez syntazę NO (eNOS) w śródbłonku z argininy. Dyfunduje do mięśni gładkich naczyń → aktywacja cGMP → rozkurcz naczyń. Hamuje agregację płytek i adhezję leukocytów. Dysfunkcja śródbłonka z upośledzeniem NO jest wczesnym etapem miażdżycy.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Endotelina-1 — rola naczyniowa', 'Endotelina-1 jest najsilniejszym znanym wazokonstryktorem. Wytwarzana przez komórki śródbłonka, działa na receptory ETA (mięśnie gładkie — skurcz) i ETB (śródbłonek — wydzielanie NO). Podwyższony poziom w nadciśnieniu płucnym. Antagoniści endoteliny (bosentan) stosowani w leczeniu nadciśnienia płucnego.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opór obwodowy (SVR) — co go determinuje?', 'SVR zależy głównie od promienia naczyń oporowych (arterioli) zgodnie z prawem Poiseuille''a (R ∝ 1/r⁴). Regulacja: układ współczulny (noradrenalina → α1 → skurcz), NO i prostacyklina (rozkurcz), angiotensyna II (skurcz). MAP = CO × SVR, więc SVR bezpośrednio wpływa na ciśnienie.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Poiseuille''a — zastosowanie hemodynamiczne', 'Przepływ Q = (ΔP × π × r⁴) / (8 × η × L). Promień naczynia (r) ma największy wpływ — zmiana o 50% zmienia przepływ 16-krotnie. Zwiększona lepkość krwi (η, np. czerwienica) zwiększa opór. Prawo tłumaczy, dlaczego skurcz arterioli drastycznie zmniejsza perfuzję.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Laplace''a dla naczyń', 'Napięcie ściany (T) = P × r / grubość ściany. Duże, rozszerzone naczynia (tętniaki) mają większe napięcie ściany przy tym samym ciśnieniu → ryzyko pęknięcia. Kapilarny mały promień pozwala wytrzymać ciśnienie mimo cienkich ścian.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mikrokrążenie — wymiana przezkapilarną (hipoteza Starlinga)', 'Filtracja netto zależy od: ciśnienia hydrostatycznego kapilarnego (wypycha płyn) i onkotycznego osocza (zatrzymuje płyn). Jnet = Kf [(Pc − Pi) − σ(πc − πi)]. Na końcu tętniczym kapilary dominuje filtracja, na żylnym — reabsorpcja. Zaburzenia powodują obrzęki.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obrzęk — patofizjologia', 'Obrzęk to nadmierne gromadzenie płynu w przestrzeni śródmiąższowej. Przyczyny: wzrost ciśnienia hydrostatycznego (niewydolność serca), spadek ciśnienia onkotycznego (hipoalbuminemia), wzrost przepuszczalności naczyń (zapalenie), upośledzenie drenażu limfatycznego (obrzęk limfatyczny).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Powrót żylny — mechanizmy wspomagające', 'Powrót żylny jest wspomagany przez: pompę mięśniową (skurcz mięśni szkieletowych), zastawki żylne (zapobiegają cofaniu), pompę oddechową (ujemne ciśnienie w klatce piersiowej na wdechu), tonus żylny (regulacja współczulna). Unieruchomienie zmniejsza powrót żylny → ryzyko zakrzepicy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie płucne — cechy hemodynamiczne', 'Krążenie płucne jest niskociśnieniowe (PAP skurczowe ~25 mmHg, średnie ~15 mmHg) i niskooporowe. Naczynia płucne reagują na hipoksję wazokonstrykcją (odruch Eulera-Liljestrandta) — to odwrotnie niż systemowe. Chronicza hipoksja prowadzi do nadciśnienia płucnego i przerostu prawej komory.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hipoksyjna wazokonstrykcja płucna (odruch Eulera-Liljestrandta)', 'W odpowiedzi na hipoksję pęcherzykową naczynia płucne kurczą się, kierując krew do lepiej wentylowanych obszarów. Mechanizm: hamowanie kanałów K⁺ w mięśniach gładkich → depolaryzacja → napływ Ca²⁺. Jest to odwrotność reakcji naczyń systemowych i optymalizuje stosunek V/Q.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie mózgowe — autoregulacja', 'Przepływ mózgowy (CBF) jest utrzymywany stały (~750 ml/min) przy MAP 60–150 mmHg dzięki autoregulacji miogennej i metabolicznej. CO₂ jest najsilniejszym regulatorem — hiperkapnia rozszerza naczynia mózgowe, hipokapnia je zwęża. Poniżej MAP 60 mmHg autoregulacja zawodzi → niedokrwienie.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie nerkowe — autoregulacja', 'Przepływ nerkowy (~1200 ml/min, ~25% CO) jest autoregulowany przy MAP 80–180 mmHg. Mechanizmy: odpowiedź miogenna (efekt Baylissa) i sprzężenie cewkowo-kłębuszkowe (macula densa — adenozyna). Poniżej MAP 80 mmHg GFR spada. Angiotensyna II zwęża tętniczkę odprowadzającą, podtrzymując GFR przy niskim ciśnieniu.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wpływ układu współczulnego na serce', 'Stymulacja współczulna (noradrenalina → receptory β1): efekt chronotropowy dodatni (wzrost HR), inotropowy dodatni (wzrost kurczliwości), dromotropowy dodatni (przyspieszenie przewodzenia AV), luzytropowy dodatni (przyspieszenie rozkurczu). Mechanizm: cAMP → PKA → fosforylacja kanałów Ca²⁺ i fosfolambanu.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wpływ układu przywspółczulnego na serce', 'Nerw błędny (acetylocholina → receptory M2): efekt chronotropowy ujemny (zmniejszenie HR), dromotropowy ujemny (spowolnienie przewodzenia AV). Minimalny wpływ na kurczliwość komór (mało unerwienia wagalnego). Mechanizm: otwarcie kanałów K⁺-ACh → hiperpolaryzacja, hamowanie If i kanałów Ca²⁺.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Receptory adrenergiczne w układzie krążenia', 'α1 — mięśnie gładkie naczyń → wazokonstrykcja. β1 — serce → wzrost HR i kurczliwości. β2 — mięśnie gładkie naczyń (mięśnie szkieletowe, wieńcowe) → wazodylatacja. Adrenalina w niskich stężeniach pobudza głównie β2 (wazodylatacja), w wysokich α1 (wazokonstrykcja).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fazy cyklu serca — diagram Wiggera', 'Diagram Wiggera pokazuje jednoczesne zmiany ciśnień (aorta, komora, przedsionek), objętości komory, EKG, fonokardiogramu w czasie. Pozwala zrozumieć: otwarcie/zamknięcie zastawek, tony serca, fazy skurczu i rozkurczu. Kluczowe punkty: S1 przy zamknięciu zastawek AV, S2 przy zamknięciu zastawek półksiężycowatych.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wpływ wysiłku fizycznego na układ krążenia', 'Wysiłek: wzrost HR (do ~200/min), wzrost SV (do ~120 ml), wzrost CO (do 25 L/min). Wazodylatacja w mięśniach (metabolity, NO), wazokonstrykcja w nerkach i jelitach. Spadek SVR mimo wzrostu CO. SBP rośnie, DBP pozostaje stałe lub lekko spada. Redystrybucja przepływu krwi.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs kardiogenny — patofizjologia', 'Wstrząs kardiogenny to niewydolność pompy sercowej (najczęściej rozległy zawał, > 40% LV). Spadek CO → hipotonia → aktywacja współczulna i RAAS → wzrost SVR i retencja płynów → dalsze obciążenie serca → błędne koło. Objawy: hipotonia, tachykardia, zastój w płucach, zimne kończyny. Śmiertelność ~40%.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Objętość oddechowa (TV — tidal volume)', 'Objętość powietrza wdychana i wydychana podczas spokojnego oddychania. Wartość prawidłowa: ok. 500 ml. Część TV (~150 ml) wypełnia przestrzeń martwą anatomiczną i nie uczestniczy w wymianie gazowej.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapasowa objętość wdechowa (IRV)', 'Maksymalna dodatkowa objętość powietrza, którą można wciągnąć ponad spokojny wdech. Wynosi ok. 3000 ml. IRV stanowi rezerwę wentylacyjną wykorzystywaną przy wysiłku fizycznym.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapasowa objętość wydechowa (ERV)', 'Maksymalna dodatkowa objętość powietrza, którą można wydmuchać po spokojnym wydechu. Wynosi ok. 1100 ml. ERV jest zmniejszona u osób otyłych i w ciąży z powodu uniesienia przepony.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Objętość zalegająca (RV — residual volume)', 'Objętość powietrza pozostająca w płucach po maksymalnym wydechu. Wynosi ok. 1200 ml. Nie można jej zmierzyć spirometrem — wymaga pletyzmografii lub rozcieńczenia helem. RV jest zwiększona w rozedmie i obturacji.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pojemność życiowa (VC — vital capacity)', 'VC = TV + IRV + ERV ≈ 4600 ml. Maksymalna objętość powietrza, którą można wydmuchać po maksymalnym wdechu. Zmniejszona w chorobach restrykcyjnych (zwłóknienie, deformacje klatki piersiowej) i ciężkiej obturacji.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Całkowita pojemność płuc (TLC)', 'TLC = VC + RV ≈ 5800 ml. Objętość powietrza w płucach po maksymalnym wdechu. Zwiększona w rozedmie (hiperinflacja). Zmniejszona w chorobach restrykcyjnych.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czynnościowa pojemność zalegająca (FRC)', 'FRC = ERV + RV ≈ 2300 ml. Objętość powietrza w płucach po spokojnym wydechu. Punkt równowagi sił sprężystych płuc i klatki piersiowej. FRC jest zwiększona w obturacji (pułapka powietrzna) i zmniejszona w restrykcji.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('FEV1 i FVC — interpretacja', 'FEV1 — objętość wydmuchana w 1. sekundzie natężonego wydechu. FVC — całkowita objętość natężonego wydechu. FEV1/FVC (wskaźnik Tiffeneau): norma > 0,70. Obniżony w obturacji (astma, POChP). W restrykcji oba zmniejszone, ale stosunek prawidłowy lub podwyższony.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przestrzeń martwa anatomiczna i fizjologiczna', 'Przestrzeń martwa anatomiczna (~150 ml): drogi oddechowe bez wymiany gazowej (nos, gardło, tchawica, oskrzela). Przestrzeń martwa fizjologiczna = anatomiczna + pęcherzykowa (pęcherzyki wentylowane, ale nieperfundowane). U zdrowych obie są prawie równe.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wentylacja minutowa i pęcherzykowa', 'Wentylacja minutowa (VE) = TV × częstość oddechów = 500 × 12 = 6000 ml/min. Wentylacja pęcherzykowa (VA) = (TV − Vd) × f = (500 − 150) × 12 = 4200 ml/min. VA jest kluczowa dla wymiany gazowej. Oddychanie szybkie i płytkie zwiększa VE, ale zmniejsza VA.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wymiana gazowa — dyfuzja przez barierę pęcherzykowo-włośniczkową', 'Bariery: nabłonek pęcherzykowy (typ I), błona podstawna pęcherzyka, błona podstawna kapilary, śródbłonek. Grubość ~0,5 μm. Dyfuzja zgodnie z prawem Ficka: przepływ ∝ (powierzchnia × ΔP) / grubość. Powierzchnia wymiany: ~70 m². O₂ i CO₂ osiągają równowagę w ~0,25 s (czas tranzytu ~0,75 s).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ciśnienia parcjalne gazów w powietrzu pęcherzykowym', 'PAO₂ ≈ 100 mmHg, PACO₂ ≈ 40 mmHg. W krwi żylnej mieszanej: PvO₂ ≈ 40 mmHg, PvCO₂ ≈ 46 mmHg. Gradient ciśnień napędza dyfuzję O₂ do krwi (ΔP = 60 mmHg) i CO₂ do pęcherzyków (ΔP = 6 mmHg). CO₂ dyfunduje 20× szybciej niż O₂ dzięki wyższej rozpuszczalności.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równanie gazowe pęcherzykowe (uproszczone)', 'PAO₂ = FiO₂ × (Patm − PH₂O) − PACO₂/R. Przy oddychaniu powietrzem: PAO₂ = 0,21 × (760 − 47) − 40/0,8 ≈ 100 mmHg. R (współczynnik oddechowy) = VCO₂/VO₂ ≈ 0,8. Gradient pęcherzykowo-tętniczy (A-a) prawidłowo < 15 mmHg. Zwiększony A-a gradient sugeruje zaburzenia dyfuzji lub shunt.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stosunek wentylacji do perfuzji (V/Q)', 'Idealny V/Q = 1. W pozycji stojącej: szczyty płuc V/Q > 1 (nadmierna wentylacja względem perfuzji), podstawy V/Q < 1 (nadmierna perfuzja). Średni V/Q ≈ 0,8. V/Q = 0: shunt (perfuzja bez wentylacji). V/Q = ∞: przestrzeń martwa (wentylacja bez perfuzji).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Shunt prawo-lewy — wpływ na PaO₂', 'Shunt to przepływ krwi omijający wentylowane pęcherzyki (V/Q = 0). Przyczyny: niedodma, zapalenie płuc, wrodzone wady serca. Hipoksemia z powodu shuntu NIE odpowiada na tlenoterapię 100% O₂ (krew shuntowa nie kontaktuje się z pęcherzykami). To odróżnia shunt od zaburzeń V/Q.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krzywa dysocjacji hemoglobiny — kształt i znaczenie', 'Krzywa ma kształt sigmoidalny dzięki kooperatywności wiązania O₂. Plateau (PO₂ > 60 mmHg): Hb prawie wysycona — zabezpieczenie przed hipoksją. Stroma część (PO₂ 20–60 mmHg): duże uwalnianie O₂ w tkankach. P50 = PO₂ przy 50% saturacji ≈ 26,7 mmHg.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Efekt Bohra', 'Spadek pH (wzrost H⁺) lub wzrost PCO₂ przesuwa krzywą dysocjacji Hb w prawo → zmniejszone powinowactwo Hb do O₂ → łatwiejsze uwalnianie O₂ w tkankach. Znaczenie kliniczne: aktywne tkanki (wysiłek, zapalenie) produkują CO₂ i kwas mlekowy → ułatwione dostarczanie O₂.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przesunięcie krzywej dysocjacji Hb w prawo', 'Przesunięcie w prawo (mniejsze powinowactwo do O₂): wzrost temperatury, wzrost PCO₂, spadek pH, wzrost 2,3-DPG. Klinicznie: ułatwia oddawanie O₂ tkankome. 2,3-DPG wzrasta w anemii, na wysokości, w hipofosfatemii jest obniżone.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przesunięcie krzywej dysocjacji Hb w lewo', 'Przesunięcie w lewo (większe powinowactwo do O₂): spadek temperatury, spadek PCO₂, wzrost pH, spadek 2,3-DPG, hemoglobina płodowa (HbF), karboksyhemoglobina (CO). Utrudnia oddawanie O₂ tkankom. Zatrucie CO: Hb chętnie wiąże O₂, ale nie oddaje go.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Transport CO₂ we krwi', 'CO₂ jest transportowany w trzech formach: rozpuszczony w osoczu (~7%), jako wodorowęglan HCO₃⁻ (~70%, konwersja przez anhydrazę węglanową w erytrocytach), jako karbaminohemoglobina (~23%, wiązanie z NH₂ Hb). Efekt Haldane''a: odtlenowana Hb wiąże więcej CO₂.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Efekt Haldane''a', 'Deoksyhemoglobina ma większe powinowactwo do CO₂ i H⁺ niż oksyhemoglobina. W tkankach (niska PO₂): Hb oddaje O₂ i chętniej wiąże CO₂. W płucach (wysoka PO₂): Hb wiąże O₂ i uwalnia CO₂. Efekt Haldane''a odpowiada za ~50% wymiany CO₂.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Surfaktant płucny — funkcja i skład', 'Surfaktant produkowany przez pneumocyty typu II, główny składnik: dipalmitoilofosfatydylocholina (DPPC). Zmniejsza napięcie powierzchniowe w pęcherzykach, zapobiega ich zapadaniu (niedodmie). Stabilizuje małe pęcherzyki (prawo Laplace''a: P = 2T/r). Niedobór u wcześniaków → zespół zaburzeń oddychania (RDS).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Laplace''a w kontekście pęcherzyków płucnych', 'P = 2T/r, gdzie T = napięcie powierzchniowe, r = promień. Małe pęcherzyki miałyby większe ciśnienie i zapadały się (wydmuchując powietrze do dużych). Surfaktant redukuje T bardziej w małych pęcherzykach (większe stężenie na mniejszej powierzchni), wyrównując ciśnienie i stabilizując wentylację.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Podatność płuc (compliance)', 'Podatność = ΔV/ΔP — zmiana objętości na jednostkę zmiany ciśnienia. Wysoka podatność: płuca łatwo się rozciągają (rozedma — destrukcja elastyny). Niska podatność: płuca sztywne (zwłóknienie, brak surfaktantu, obrzęk). Podatność zmniejsza się przy dużych i małych objętościach płuc.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opór dróg oddechowych', 'Największy opór w oskrzelach średniego kalibru (4–8 generacja). Oskrzeliki końcowe mają mały indywidualny opór, ale ogromna ich liczba daje niski opór łączny. Regulacja: układ współczulny (β2 → rozkurcz), przywspółczulny (M3 → skurcz). W astmie: skurcz mięśni gładkich + obrzęk + wydzielina → zwiększony opór.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ośrodek oddechowy w pniu mózgu', 'Ośrodek oddechowy w rdzeniu przedłużonym: grupa grzbietowa (DRG — wdech, n. przeponowy), grupa brzuszna (VRG — natężony wydech). Most: ośrodek pneumotaksyczny (hamuje wdech, przyspiesza oddech), ośrodek apneustyczny (pobudza wdech). Rdzeń zapewnia rytm, most moduluje.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chemoreceptory centralne', 'Chemoreceptory centralne leżą na brzusznej powierzchni rdzenia przedłużonego. Reagują na wzrost H⁺ w płynie mózgowo-rdzeniowym (pochodzący z CO₂ — CO₂ przenika przez barierę krew-mózg, tworzy H⁺ via anhydraza węglanowa). PCO₂ jest głównym regulatorem wentylacji w warunkach fizjologicznych.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chemoreceptory obwodowe', 'Kłębki szyjne (n. IX — językowo-gardłowy) i aortalne (n. X — błędny). Reagują na spadek PaO₂ (głównie < 60 mmHg), wzrost PaCO₂ i spadek pH. Kłębki szyjne są głównym sensorem hipoksji. U pacjentów z POChP z chroniczną hiperkapnią, hipoksja staje się głównym bodźcem oddechowym (uwaga przy tlenoterapii!).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odpowiedź wentylacyjna na CO₂', 'Wzrost PaCO₂ o 1 mmHg zwiększa wentylację minutową o ~2–3 L/min (via chemoreceptory centralne). Jest to najsilniejszy bodziec wentylacyjny. Odpowiedź jest osłabiona przez: sen, narkotyki, znieczulenie, POChP z przewlekłą hiperkapnią. Hipoksja i kwasica nasilają odpowiedź na CO₂.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odpowiedź wentylacyjna na hipoksję', 'Istotna stymulacja wentylacji pojawia się przy PaO₂ < 60 mmHg (chemoreceptory obwodowe — kłębki szyjne). Powyżej PaO₂ 60 mmHg (plateau krzywej dysocjacji) — minimalna stymulacja. U pacjentów z POChP i chroniczną hiperkapnią hipoksja może być jedynym bodźcem oddechowym — podanie 100% O₂ grozi bezdechem.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mięśnie oddechowe', 'Główny mięsień wdechowy: przepona (n. przeponowy C3-C5). Pomocnicze wdechowe: mięśnie międzyżebrowe zewnętrzne, mostkowo-obojczykowo-sutkowe, pochyłe. Spokojny wydech jest bierny (sprężystość płuc). Natężony wydech: mięśnie brzuszne, mięśnie międzyżebrowe wewnętrzne.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ciśnienie wewnątrzopłucnowe', 'Ciśnienie wewnątrzopłucnowe jest ujemne (ok. −5 cmH₂O na końcu spokojnego wydechu) z powodu przeciwnych sił sprężystych płuc (do wewnątrz) i klatki piersiowej (na zewnątrz). Staje się bardziej ujemne na wdechu (−8 cmH₂O). Odma opłucnowa (powietrze w jamie opłucnej) znosi ujemne ciśnienie → zapadnięcie płuca.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odma opłucnowa prężna — mechanizm', 'Powietrze wchodzi do jamy opłucnej przez mechanizm zastawkowy (na wdechu wpływa, na wydechu nie ucieka). Narastające ciśnienie w jamie opłucnej → zapadnięcie płuca → przesunięcie śródpiersia na stronę zdrową → kompresja żył głównych → spadek powrotu żylnego i CO. Stan zagrożenia życia — wymaga odbarczenia igłą.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spirometria — wzorzec obturacyjny', 'Obturacja: FEV1 zmniejszone, FVC prawidłowe lub lekko zmniejszone, FEV1/FVC < 0,70. Krzywa przepływ-objętość: wklęsła faza wydechowa. Przyczyny: astma (odwracalna po bronchodylatatynie), POChP (nieodwracalna). Test odwracalności: poprawa FEV1 > 12% i > 200 ml po salbutamolu.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spirometria — wzorzec restrykcyjny', 'Restrykcja: FVC zmniejszone, FEV1 zmniejszone, FEV1/FVC prawidłowy lub podwyższony (> 0,70). TLC zmniejszona (wymaga pletyzmografii do potwierdzenia). Przyczyny: zwłóknienie płuc, choroby nerwowo-mięśniowe, deformacja klatki piersiowej, otyłość, wysięk opłucnowy.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równowaga kwasowo-zasadowa — rola płuc', 'Płuca regulują PaCO₂, a CO₂ + H₂O ⇌ H₂CO₃ ⇌ H⁺ + HCO₃⁻. Hiperkapnia → kwasica oddechowa. Hipokapnia → zasadowica oddechowa. Kompensacja jest szybka (minuty). Pacjent z kwasicą metaboliczną hiperwentyluje (oddech Kussmaula), obniżając PaCO₂ kompensacyjnie.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwasica oddechowa — przyczyny i kompensacja', 'Przyczyna: retencja CO₂ (hipowentylacja) — POChP, depresja ośrodka oddechowego, choroby nerwowo-mięśniowe. Gazometria: pH < 7,35, PaCO₂ > 45 mmHg. Kompensacja nerkowa (wolna, 3–5 dni): zwiększona reabsorpcja HCO₃⁻ i wydzielanie H⁺. Ostra: ΔpH duże. Przewlekła: ΔpH minimalne.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hipoksemia — przyczyny (5 mechanizmów)', '1. Niska FiO₂ (wysokość). 2. Hipowentylacja (wzrost PACO₂ → spadek PAO₂). 3. Zaburzenia dyfuzji (zwłóknienie). 4. Niedopasowanie V/Q (POChP, astma). 5. Shunt prawo-lewy (niedodma, ASD/VSD). Tylko shunt nie poprawia się przy 100% O₂. Gradient A-a prawidłowy w hipowentylacji i niskiej FiO₂; podwyższony w pozostałych.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemoglobina płodowa (HbF) — znaczenie', 'HbF (α₂γ₂) ma wyższe powinowactwo do O₂ niż HbA (α₂β₂), ponieważ łańcuchy γ słabo wiążą 2,3-DPG. Krzywa dysocjacji przesunięta w lewo. Ułatwia to transport O₂ z krwi matki do płodu przez łożysko. HbF stanowi ~60% Hb noworodka, spada do < 2% do 6. miesiąca życia.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wysokość — adaptacja oddechowa', 'Na wysokości spada ciśnienie atmosferyczne → niższe PiO₂ i PAO₂ → hipoksja. Ostra adaptacja: hiperwentylacja (chemoreceptory obwodowe) → spadek PaCO₂ → zasadowica oddechowa. Przewlekła: wzrost 2,3-DPG, poliglobulia (erytropoetyna), przebudowa naczyń płucnych. Choroba wysokościowa: obrzęk mózgu i płuc.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Potencjał spoczynkowy neuronu — wartość i mechanizm', 'Potencjał spoczynkowy wynosi ok. −70 mV (wnętrze komórki ujemne). Utrzymywany przez: pompę Na⁺/K⁺-ATPazę (3 Na⁺ na zewnątrz, 2 K⁺ do wewnątrz), dominującą przepuszczalność dla K⁺ (kanały nieszczelne K⁺) i równowagę Donnana. Równanie Nernsta dla K⁺: EK ≈ −90 mV.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równanie Nernsta', 'E = (RT/zF) × ln([ion]zewn/[ion]wewn). Dla K⁺ w 37°C: EK = 61,5 × log(4/140) ≈ −90 mV. Dla Na⁺: ENa = 61,5 × log(140/14) ≈ +60 mV. Potencjał spoczynkowy bliższy EK, bo błona jest bardziej przepuszczalna dla K⁺.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równanie Goldmana-Hodgkina-Katza', 'Uwzględnia przepuszczalności dla wielu jonów: Vm = (RT/F) × ln[(PK[K⁺]e + PNa[Na⁺]e + PCl[Cl⁻]i) / (PK[K⁺]i + PNa[Na⁺]i + PCl[Cl⁻]e)]. Dokładniejsze niż równanie Nernsta, bo uwzględnia względne przepuszczalności. W spoczynku PK >> PNa, więc Vm bliskie EK.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pompa Na⁺/K⁺-ATPaza', 'Transportuje 3 Na⁺ na zewnątrz i 2 K⁺ do wewnątrz komórki, zużywając 1 ATP. Jest elektrogeniczna (netto ujemny prąd do wewnątrz). Utrzymuje gradient jonowy niezbędny dla potencjałów i transportu wtórnego. Hamowana przez glikozydy nasercowe (digoksyna) i brak ATP.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Potencjał czynnościowy — faza depolaryzacji', 'Bodziec progowy depolaryzuje błonę do ~−55 mV → otwieranie bramek aktywacyjnych kanałów Na⁺ (napięciowo-zależnych) → szybki napływ Na⁺ → dalsze otwarcie kanałów (sprzężenie zwrotne dodatnie) → szczyt +30 mV (zbliża się do ENa). Faza trwa ~0,5 ms. Zasada „wszystko albo nic".', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Potencjał czynnościowy — faza repolaryzacji', 'Po ~0,5 ms bramki inaktywacyjne kanałów Na⁺ zamykają się (inaktywacja). Jednocześnie otwierają się kanały K⁺ napięciowo-zależne (opóźniony prąd wyprostowujący) → wypływ K⁺ → potencjał wraca do wartości ujemnych. Hiperpolaryzacja przejściowa (undershoot) poniżej −70 mV, bo kanały K⁺ zamykają się wolno.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Okres refrakcji bezwzględnej i względnej', 'Bezwzględny: kanały Na⁺ inaktywowane, żaden bodziec nie wywoła PA. Zapewnia jednokierunkowe przewodzenie i maksymalną częstotliwość impulsów. Względny: część kanałów Na⁺ odzyskała stan spoczynkowy, silniejszy bodziec może wywołać PA (mniejsza amplituda). Okres refrakcji chroni przed tetanizacją nerwy i mięsień sercowy.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przewodzenie skokowe (saltatory conduction)', 'W włóknach mielinowych PA przeskakuje między przewężeniami Ranviera (jedyne miejsca z kanałami Na⁺). Prąd lokalny depolaryzuje następne przewężenie. Szybkość: 5–120 m/s (proporcjonalna do średnicy). Znacznie szybsze i energooszczędne niż ciągłe przewodzenie we włóknach bezmielinowych (0,5–2 m/s).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mielinizacja — rola i patologia', 'Mielina tworzona przez oligodendrocyty (OUN) i komórki Schwanna (obwodowy UN). Izoluje akson, zwiększa szybkość przewodzenia. Stwardnienie rozsiane (SM): demielinizacja OUN → zaburzenia przewodzenia, objawy wieloogniskowe. Zespół Guillaina-Barrégo: demielinizacja obwodowa → wstępujące porażenie.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synapsa chemiczna — etapy transmisji', '1. PA dociera do zakończenia presynaptycznego. 2. Otwarcie kanałów Ca²⁺ napięciowo-zależnych. 3. Napływ Ca²⁺ → fuzja pęcherzyków z błoną (via SNARE). 4. Egzocytoza neuroprzekaźnika do szczeliny synaptycznej. 5. Wiązanie z receptorami postsynaptycznymi. 6. Inaktywacja: wychwyt zwrotny, degradacja enzymatyczna, dyfuzja.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('EPSP i IPSP', 'EPSP (pobudzający potencjał postsynaptyczny): depolaryzacja przez napływ Na⁺ lub Ca²⁺ (np. glutaminian → AMPA). IPSP (hamujący): hiperpolaryzacja przez napływ Cl⁻ lub wypływ K⁺ (np. GABA → GABA-A). Sumowanie przestrzenne i czasowe EPSP/IPSP na wzgórku aksonu decyduje, czy powstanie PA.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Acetylocholina (ACh) — receptory i funkcje', 'Receptory nikotynowe (jonotropowe, kanał Na⁺): złącze nerwowo-mięśniowe, zwoje autonomiczne, OUN. Receptory muskarynowe (metabotropowe, G-protein): M1 (OUN, żołądek), M2 (serce — bradykardia), M3 (mięśnie gładkie, gruczoły — skurcz, wydzielanie). ACh rozkładany przez acetylocholinesterazę (AChE).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dopamina — szlaki i znaczenie kliniczne', 'Szlaki dopaminergiczne: 1. Nigrostriatalna (SN → striatum) — kontrola ruchu, ubytek → Parkinson. 2. Mezolimbiczna (VTA → nucleus accumbens) — nagroda, nadmiar → psychoza. 3. Mezokortykalna (VTA → kora przedczołowa) — funkcje poznawcze. 4. Tuberoinfundibularna (podwzgórze → przysadka) — hamowanie prolaktyny.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Serotonina (5-HT) — funkcje i znaczenie', 'Serotonina syntetyzowana z tryptofanu (jądra szwu w pniu mózgu). Reguluje nastrój, sen, apetyt, ból. Receptory: 5-HT1A (anksjoliza), 5-HT2A (halucynacje), 5-HT3 (nudności). Niedobór → depresja. SSRI (fluoksetyna) hamują wychwyt zwrotny 5-HT. 90% serotoniny w komórkach enterochromafinowych jelita.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('GABA — główny neuroprzekaźnik hamujący OUN', 'GABA (kwas γ-aminomasłowy) syntetyzowany z glutaminianu (GAD — dekarboksylaza glutaminianowa). Receptor GABA-A: kanał Cl⁻ (szybkie hamowanie). Miejsce wiązania benzodiazepin (nasilają działanie GABA), barbituranów, etanolu. Receptor GABA-B: metabotropowy (kanał K⁺, hamowanie presynaptyczne). Deficyt GABA → drgawki.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glutaminian — główny neuroprzekaźnik pobudzający OUN', 'Receptory jonotropowe: AMPA (szybki EPSP, kanał Na⁺), NMDA (Ca²⁺/Na⁺, zależny od napięcia — blok Mg²⁺, kluczowy w LTP i pamięci), kainianowe. Receptory metabotropowe (mGluR). Nadmiar glutaminianu → ekscytotoksyczność (śmierć neuronów przez nadmiar Ca²⁺) — udar, urazy, choroby neurodegeneracyjne.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Noradrenalina — funkcje ośrodkowe i obwodowe', 'Ośrodkowo: jądro sinawego (locus coeruleus) → czuwanie, uwaga, reakcja na stres. Obwodowo: neuroprzekaźnik pozazwojowych neuronów współczulnych. Receptory α1 (wazokonstrykcja), α2 (presynaptyczne hamowanie wydzielania NA), β1 (serce — tachykardia, wzrost kurczliwości), β2 (rozkurcz oskrzeli, naczyń).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Endorfiny i enkefaliny — układ opioidowy', 'Endogenne opioidy: endorfiny (β-endorfina — przysadka), enkefaliny (rdzeń, jelita), dynorfiny. Receptory: μ (analgezja, euforia, depresja oddechowa), κ (analgezja, dysforia), δ (modulacja). Morfina i inne opioidy działają na receptory μ. System endokanabinoidowy współdziała z opioidowym w modulacji bólu.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ współczulny — przegląd', 'Neurony przedzwojowe: rdzeń kręgowy Th1-L2, krótkie, ACh → receptory nikotynowe na zwojach. Neurony pozazwojowe: długie, noradrenalina (wyjątek: ACh w gruczołach potowych ekrynowych). Rdzeń nadnerczy: uwalnia adrenalinę (80%) i noradrenalinę (20%). Reakcja „walcz lub uciekaj": tachykardia, rozszerzenie źrenic, rozszerzenie oskrzeli.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ przywspółczulny — przegląd', 'Neurony przedzwojowe: pień mózgu (nn. III, VII, IX, X) i rdzeń krzyżowy (S2-S4), długie, ACh → receptory nikotynowe. Neurony pozazwojowe: krótkie, ACh → receptory muskarynowe. Nerw błędny (X) unerwia narządy klatki piersiowej i jamy brzusznej. Odpoczynek i trawienie: bradykardia, perystaltyka, zwężenie źrenicy.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nerw błędny (n. X) — funkcje', 'Najdłuższy nerw czaszkowy. Unerwienie przywspółczulne: serce (bradykardia), płuca (skurcz oskrzeli), przewód pokarmowy (perystaltyka, wydzielanie). Komponenta czuciowa: gardło, krtań, narządy wewnętrzne. Ruchowa: mięśnie krtani i gardła. Stymulacja wagalna: odruch okulokardialny, manewr Valsalvy.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nerwy czaszkowe — I do VI', 'I (węchowy): węch. II (wzrokowy): wzrok. III (okoruchowy): ruchy gałki ocznej, zwężenie źrenicy, akomodacja. IV (bloczkowy): m. skośny górny. V (trójdzielny): czucie twarzy, żucie (V3). VI (odwodzący): m. prostych boczny. Zapamiętywanie: „Oh Oh Oh To Touch And Feel...".', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nerwy czaszkowe — VII do XII', 'VII (twarzowy): mimika, smak 2/3 języka, łzawienie, ślinianki. VIII (przedsionkowo-ślimakowy): słuch, równowaga. IX (językowo-gardłowy): smak 1/3 języka, zatoka szyjna. X (błędny): narządy wewnętrzne. XI (dodatkowy): m. czworoboczny, mostkowo-obojczykowo-sutkowy. XII (podjęzykowy): ruchy języka.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bariera krew-mózg (BBB)', 'Tworzona przez śródbłonek naczyń mózgowych z tight junctions, otoczony stopkami astrocytów i pericytami. Przepuszcza: O₂, CO₂, małe lipofilne cząsteczki, glukozę (GLUT1), aminokwasy (transportery). Nie przepuszcza: białek osocza, dużych hydrofilnych leków, wielu antybiotyków. Zaburzenie BBB: zapalenie, guzy, udar.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Płyn mózgowo-rdzeniowy (CSF) — produkcja i krążenie', 'CSF produkowany przez sploty naczyniówkowe komór (500 ml/dobę, objętość ~150 ml). Krąży: komory boczne → otwory Monro → komora III → wodociąg mózgu → komora IV → otwory Luschki i Magendiego → przestrzeń podpajęczynówkowa → kosmki pajęczynówki → zatoki żylne. Wodogłowie: zablokowanie odpływu.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Długotrwałe wzmocnienie synaptyczne (LTP)', 'LTP to trwałe wzmocnienie transmisji synaptycznej po intensywnej stymulacji, podstawa uczenia i pamięci. Mechanizm w hipokampie: silna depolaryzacja → usunięcie bloku Mg²⁺ z kanału NMDA → napływ Ca²⁺ → aktywacja CaMKII → wbudowanie dodatkowych receptorów AMPA → silniejsza odpowiedź na glutaminian.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hipokamp — rola w pamięci', 'Hipokamp (płat skroniowy przyśrodkowy) jest kluczowy dla konsolidacji pamięci krótkotrwałej w długotrwałą (pamięć deklaratywna — fakty i zdarzenia). Uszkodzenie obustronne → amnezja następcza (brak tworzenia nowych wspomnień). Pamięć proceduralna (umiejętności ruchowe) zależy od jąder podstawy i móżdżku.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jądra podstawy — funkcja i patologia', 'Jądra podstawy (striatum, globus pallidus, substantia nigra, nucleus subthalamicus) modulują ruchy dobrowolne, planowanie ruchu i selekcję działań. Szlak bezpośredni (D1) → ułatwianie ruchu. Szlak pośredni (D2) → hamowanie ruchu. Choroba Parkinsona: utrata neuronów dopaminergicznych SN → hipokinezja, sztywność, drżenie spoczynkowe.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Móżdżek — funkcje', 'Kora móżdżku: koordynacja ruchów, równowaga, napięcie mięśniowe, uczenie ruchowe. Archicerebellum (kłaczkowo-grudkowy): równowaga, ruchy oczu. Paleocerebellum (robak): napięcie, chód. Neocerebellum (półkule): koordynacja ruchów precyzyjnych. Uszkodzenie: ataksja, dysmetria, adiadochokinezja, nystagmus, mowa skandowana.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kora ruchowa — organizacja', 'Kora ruchowa pierwotna (M1, pole 4): wykonanie ruchu, organizacja somatotopowa (homunculus ruchowy). Kora przedruchowa (pole 6): planowanie ruchów. Dodatkowa kora ruchowa (SMA): sekwencje ruchowe. Aksony: droga korowo-rdzeniowa (piramidowa), skrzyżowanie w rdzeniu przedłużonym → kontrola kontralateralna.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Droga piramidowa (korowo-rdzeniowa)', 'Zaczyna się w korze ruchowej → torebka wewnętrzna → szypuła mózgu → most → piramidy rdzenia przedłużonego (90% skrzyżowanie — tractus corticospinalis lateralis). Uszkodzenie neuronu górnego: spastyczność, wygórowane odruchy, objaw Babińskiego. Uszkodzenie neuronu dolnego: wiotkie porażenie, zanik mięśni, fascykulacje.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kora czuciowa somatyczna — organizacja', 'Kora S1 (zakręt zaśrodkowy, pola 3,1,2): odbiór czucia dotyku, bólu, temperatury, propriocepcji. Organizacja somatotopowa (homunculus czuciowy — największa reprezentacja: dłoń, usta, twarz). Informacja dochodzi przez wzgórze (jądro VPL — tułów/kończyny, VPM — twarz).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Droga czucia dotyku i propriocepcji (sznury tylne)', 'Receptory → neuron I (zwój rdzeniowy) → sznury tylne (fasciculus gracilis — kończyny dolne, cuneatus — górne) → jądra smukłe/klinowate (rdzeń przedłużony) → skrzyżowanie → lemnisc przyśrodkowy → wzgórze (VPL) → kora S1. Przekazuje dotyk precyzyjny, wibrację, propriocepcję. Uszkodzenie: ataksja czuciowa, objaw Romberga dodatni.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Droga czucia bólu i temperatury (szlak rdzeniowo-wzgórzowy)', 'Receptory → neuron I (zwój rdzeniowy) → synaps w rogu tylnym rdzenia → skrzyżowanie (na tym samym segmencie) → sznur boczny (tractus spinothalamicus lateralis) → wzgórze (VPL) → kora S1. Ból i temperatura krzyżują się na poziomie wejścia do rdzenia. Jamistość rdzenia (syringomyelia): utrata bólu/temp. przy zachowanym dotyku.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Teoria bramki bólu (Melzacka i Walla)', 'Pobudzenie grubych włókien czuciowych Aβ (dotyk) aktywuje interneurony hamujące w substancji galaretowatej rdzenia, blokując transmisję bólu z cienkich włókien Aδ i C. Wyjaśnia, dlaczego masowanie bolesnego miejsca zmniejsza ból. Zstępujące hamowanie: szlaki z PAG (istota szara okołowodociągowa) → jądro wielkie szwu → enkefaliny/serotonina.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Włókna bólowe — typy', 'Aδ (mielinowe, szybkie, ~20 m/s): ostry, dobrze zlokalizowany „pierwszy ból". C (bezmielinowe, wolne, ~1 m/s): tępy, rozlany „drugi ból", piekący. Receptory bólowe (nocyceptory): wolne zakończenia nerwowe aktywowane przez bodźce mechaniczne, termiczne, chemiczne (bradykinina, prostaglandyny, substancja P).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ból rzutowany (referred pain)', 'Ból z narządów wewnętrznych odczuwany na powierzchni skóry. Mechanizm: włókna trzewne i somatyczne zbiegają się na tych samych neuronach rdzenia. Przykłady: zawał → ból lewego ramienia/żuchwy; zapalenie pęcherzyka żółciowego → ból prawego barku; zapalenie wyrostka → ból w okolicy pępka → prawy dół biodrowy.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch rozciągowy (miotatyczny)', 'Rozciągnięcie mięśnia → wrzeciona mięśniowe (Ia) → rdzeń kręgowy → monosynaptyczny EPSP na motoneuron α → skurcz tego samego mięśnia. Jednocześnie hamowanie reciprokalne antagonisty (via interneuron hamujący). Przykład: odruch kolanowy (uderzenie w więzadło rzepki → skurcz m. czworogłowego). Wygórowanie: uszkodzenie neuronu górnego.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch cofnięcia i skrzyżowany wyprostny', 'Bodziec bólowy → włókna Aδ/C → interneurony rdzenia → zgięcie kończyny bodźcowanej (odruch cofnięcia) + jednoczesny wyprost kończyny przeciwnej (odruch skrzyżowany wyprostny). Jest to odruch polisynaptyczny, obronny. Pozwala utrzymać równowagę przy cofaniu kończyny od bodźca.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Narząd wzroku — droga wzrokowa', 'Siatkówka → nerw wzrokowy (II) → skrzyżowanie wzrokowe (włókna nosowe krzyżują się) → pasmo wzrokowe → ciało kolankowate boczne (LGN) wzgórza → promienistość wzrokowa → kora wzrokowa pierwotna (V1, pole 17, bruzda ostrogowa). Uszkodzenie skrzyżowania (guz przysadki): niedowidzenie dwuskroniowe (bitemporal hemianopia).', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch źreniczny na światło', 'Światło → siatkówka → nerw II → jądra okolicowe (pretectum) → jądro Edingera-Westphala (obustronne) → nerw III → zwoj rzęskowy → m. zwieracz źrenicy → zwężenie źrenicy obustronne. Bezpośredni (ipsilateralny) i konsensualny (kontralateralny). RAPD (relative afferent pupillary defect) — wada dośrodkowa (uszkodzenie nerwu II).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Narząd słuchu — droga słuchowa', 'Fale dźwiękowe → błona bębenkowa → kosteczki słuchowe → okienko owalne → perylimfa (scala vestibuli) → membrana podstawna (narząd Cortiego) → komórki rzęsate → nerw VIII → jądra ślimakowe → oliwka górna → wzniesienie → ciało kolankowate przyśrodkowe → kora słuchowa (zakręt Heschla). Tonotopia zachowana na całej drodze.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ przedsionkowy — kanały półkoliste', 'Trzy kanały półkoliste w każdym uchu (przedni, tylny, boczny) wykrywają przyspieszenia kątowe (rotacje głowy). Endolimfa porusza bańkę (crista ampullaris) → odchylenie kinocilium → depolaryzacja lub hiperpolaryzacja komórek rzęsatych. Informacja via nerw VIII → jądra przedsionkowe → odruch przedsionkowo-oczny (VOR), równowaga.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Podwzgórze — funkcje', 'Podwzgórze (hypothalamus) reguluje: temperaturę ciała (termostat), pragnienie i bilans wodny (osmoreceptory), głód i sytość (jądra boczne vs brzuszno-przyśrodkowe), rytm dobowy (jądro nadskrzyżowaniowe, SCN), funkcje autonomiczne, emocje. Kontroluje przysadkę mózgową (oś podwzgórze-przysadka-narządy docelowe).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wzgórze (thalamus) — funkcje', 'Wzgórze jest „bramą do kory" — przekaźnik niemal wszystkich informacji czuciowych (wyjątek: węch). Jądra: VPL/VPM (czucie somatyczne), LGN (wzrok), MGN (słuch), VA/VL (motoryka — z móżdżku i jąder podstawy). Jądra niespecyficzne: regulacja czuwania i uwagi. Uszkodzenie → zespół wzgórzowy (ból wzgórzowy).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ limbiczny — struktury i funkcja', 'Układ limbiczny: hipokamp (pamięć), ciało migdałowate (emocje, strach), zakręt obręczy (motywacja, ból), ciała suteczkowate (pamięć). Ciało migdałowate: warunkowanie strachu, rozpoznawanie zagrożeń. Uszkodzenie bilateralne: zespół Klüvera-Bucy''ego (brak strachu, hiperoralność, hiperseksualność).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl sen-czuwanie — fazy snu', 'Sen NREM: stadium N1 (senność, fale theta), N2 (wrzeciona snu, kompleksy K), N3 (sen głęboki, fale delta — SWS). Sen REM: szybkie ruchy oczu, atonia mięśni, marzenia senne, fale EEG jak w czuwaniu. Cykl ~90 min, 4–6 cykli/noc. SWS dominuje w I połowie nocy, REM w II. SWS: konsolidacja pamięci deklaratywnej. REM: pamięć proceduralna.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Neurotransmisja w cyklu sen-czuwanie', 'Czuwanie: noradrenalina (locus coeruleus), serotonina (jądra szwu), acetylocholina (jądro podstawne Meynerta), histamina (jądro guzowo-suteczkowe), oreksyna/hipokretyna (podwzgórze boczne). Sen REM: aktywacja cholinergiczna, zahamowanie NA i 5-HT. Narkolepsja: utrata neuronów oreksynowych → napady senności i katapleksja.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki glejowe OUN — typy i funkcje', 'Astrocyty: BBB (stopki naczyniowe), wychwyt glutaminianu, homeostaza K⁺, blizna glejowa. Oligodendrocyty: mielinizacja OUN (jeden mielinizuje wiele aksonów). Mikroglej: fagocytoza, odpowiedź immunologiczna OUN (makrofagi rezydentne). Komórki wyściółki: wyściółka komór, produkcja CSF (sploty naczyniówkowe).', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Złącze nerwowo-mięśniowe — transmisja i patologia', 'PA w neuronie ruchowym → Ca²⁺ → egzocytoza ACh → receptory nikotynowe na płytce ruchowej → depolaryzacja (potencjał płytki końcowej) → PA mięśnia → skurcz. Miastenia gravis: autoprzeciwciała anty-AChR → osłabienie mięśni. Jad kiełbasiany (botulinum): hamowanie egzocytozy ACh → porażenie wiotkie. Kurara: blokada receptorów nikotynowych.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Glikoliza — lokalizacja i bilans', 'Glikoliza zachodzi w cytozolu. Glukoza → 2 pirogroniany. Bilans netto: 2 ATP (fosforylacja substratowa), 2 NADH. W warunkach tlenowych pirogronian wchodzi do mitochondriów. W beztlenowych → mleczan (dehydrogenaza mleczanowa regeneruje NAD⁺).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glikoliza — enzymy regulatorowe', 'Trzy nieodwracalne etapy: 1. Heksokinaza (glukoza → G-6-P, hamowana przez G-6-P). 2. Fosfofruktokinaza-1 (PFK-1, główny regulator — aktywowana przez AMP, fruktozo-2,6-bisfosforan; hamowana przez ATP, cytrynian). 3. Kinaza pirogronianowa (PEP → pirogronian, hamowana przez ATP, alaninę, aktywowana przez F-1,6-BP).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fruktozo-2,6-bisfosforan — rola regulacyjna', 'F-2,6-BP jest najsilniejszym aktywatorem PFK-1 (glikoliza) i inhibitorem fruktozo-1,6-bisfosfatazy (glukoneogeneza). Wytwarzany przez PFK-2/FBPazę-2 (enzym dwufunkcyjny). Insulina → defosforylacja → aktywność PFK-2 → więcej F-2,6-BP → glikoliza. Glukagon → fosforylacja → aktywność FBPazy-2 → mniej F-2,6-BP → glukoneogeneza.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kompleks dehydrogenazy pirogronianowej (PDH)', 'Pirogronian + CoA + NAD⁺ → acetylo-CoA + CO₂ + NADH. Lokalizacja: macierz mitochondrialna. Wymaga 5 koenzymów: tiamina (B1), FAD (B2), NAD⁺ (B3), CoA (B5, kwas pantotenowy), kwas liponowy. Aktywacja: piruwat, CoA, NAD⁺. Hamowanie: acetylo-CoA, NADH, ATP. Niedobór tiaminy → kwasica mleczanowa, encefalopatia Wernickego.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl Krebsa — przegląd', 'Acetylo-CoA (2C) + oksalooctan (4C) → cytrynian (6C). Cykl 8 reakcji w macierzy mitochondrium. Na 1 acetylo-CoA: 3 NADH, 1 FADH₂, 1 GTP, 2 CO₂. Enzymy regulatorowe: syntaza cytrynianowa, dehydrogenaza izocytrynianowa, dehydrogenaza α-ketoglutaranowa. Inhibitory: NADH, ATP. Aktywatory: ADP, Ca²⁺.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl Krebsa — dehydrogenaza izocytrynianowa', 'Izocytrynian → α-ketoglutaran + CO₂ + NADH. Kluczowy enzym regulatorowy cyklu Krebsa. Aktywowana allosterycznie przez ADP i Ca²⁺. Hamowana przez ATP i NADH. Jest to główny punkt kontroli szybkości cyklu, reagujący na stan energetyczny komórki.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Łańcuch transportu elektronów — kompleksy', 'Wewnętrzna błona mitochondrium. Kompleks I: NADH → ubichinon (2,5H⁺). Kompleks II: FADH₂ → ubichinon (sukcynian → fumaran, 0 H⁺). Kompleks III: ubichinon → cytochrom c (1,5H⁺). Kompleks IV: cytochrom c → O₂ → H₂O (2H⁺). Gradient protonowy napędza syntazę ATP (kompleks V).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fosforylacja oksydacyjna — bilans ATP', 'NADH → ~2,5 ATP (kompleksy I→III→IV). FADH₂ → ~1,5 ATP (kompleksy II→III→IV). 1 glukoza → glikoliza (2 NADH, 2 ATP) + 2 PDH (2 NADH) + 2 cykle Krebsa (6 NADH, 2 FADH₂, 2 GTP) = ~30–32 ATP łącznie. Zależy od wahadłowca (malate-aspartate: 2,5 ATP/NADH; glycerol-3P: 1,5 ATP/NADH).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Inhibitory łańcucha oddechowego', 'Kompleks I: rotenon, barbiturany. Kompleks III: antymycyna A. Kompleks IV: cyjanek (CN⁻), tlenek węgla (CO). Kompleks V (syntaza ATP): oligomycyna. Rozprzęgacze (np. 2,4-DNP, termogenina/UCP1): rozpraszają gradient H⁺ → energia jako ciepło, bez ATP. Termogenina w brązowej tkance tłuszczowej — termogeneza.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glukoneogeneza — lokalizacja i substraty', 'Głównie wątroba (90%), nerki (10%). Substraty: mleczan (cykl Cori), alanina (cykl alaninowy), glicerol (z lipolizy), aminokwasy glukogenne. Enzymy kluczowe (omijające nieodwracalne etapy glikolizy): karboksylaza pirogronianowa (mitochondrium), PEPCK, fruktozo-1,6-bisfosfataza, glukoza-6-fosfataza (ER). Koszt: 6 ATP + 2 GTP na glukozę.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl Cori', 'Mięśnie (beztlenowe) produkują mleczan → krew → wątroba → glukoneogeneza → glukoza → krew → mięśnie. Koszt netto: 4 ATP (wątroba zużywa 6 ATP, mięśnie zyskują 2 ATP z glikolizy). Umożliwia aktywność anaerobową mięśni kosztem energii wątroby.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glikogeneza i glikogenoliza', 'Glikogeneza: glukoza → G-6-P → G-1-P → UDP-glukoza → syntaza glikogenowa (aktywowana przez insulinę, defosforylacja). Glikogenoliza: fosforylaza glikogenowa (aktywowana przez glukagon/adrenalinę via cAMP → PKA → fosforylacja). Wątroba: utrzymanie glikemii. Mięśnie: energia lokalna (brak glukoza-6-fosfatazy).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Choroby spichrzeniowe glikogenu — przykłady', 'Von Gierke (typ I): niedobór glukoza-6-fosfatazy → hipoglikemia, hepatomegalia, kwasica mleczanowa. Pompe (typ II): niedobór α-glukozydazy lizosomalnej → kardiomiopatia. McArdle (typ V): niedobór fosforylazy mięśniowej → nietolerancja wysiłku, brak wzrostu mleczanu. Cori (typ III): niedobór enzymu odgałęziającego.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Szlak pentozofosforanowy (PPP)', 'Lokalizacja: cytosol. Faza oksydacyjna: G-6-P → rybulozo-5-P + 2 NADPH + CO₂. Enzym regulatorowy: dehydrogenaza glukozo-6-fosforanowa (G6PD). NADPH: ochrona antyoksydacyjna (redukcja glutationu), synteza kwasów tłuszczowych, sterydogeneza. Faza nieoksydacyjna: rybozo-5-P (synteza nukleotydów). Niedobór G6PD → anemia hemolityczna (brak NADPH → uszkodzenie erytrocytów przez ROS).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('β-oksydacja kwasów tłuszczowych', 'Lokalizacja: macierz mitochondrium. Transport przez CPT-I i CPT-II (karnityna). Cykl: odcięcie 2C jako acetylo-CoA. Jeden cykl daje: 1 FADH₂, 1 NADH, 1 acetylo-CoA. Kwas palmitynowy (C16): 7 cykli → 8 acetylo-CoA + 7 FADH₂ + 7 NADH → ~106 ATP (netto, po odliczeniu aktywacji). CPT-I hamowana przez malonylo-CoA (stan sytości).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ketogeneza — kiedy i gdzie?', 'Wątroba, mitochondria. Zachodzi przy nadmiarze acetylo-CoA (głodzenie, cukrzyca, dieta ketogeniczna). Acetylo-CoA → acetoacetylo-CoA → HMG-CoA → acetooctan → β-hydroksymaślan lub aceton. Ciała ketonowe: paliwo dla mózgu (nie może używać kwasów tłuszczowych bezpośrednio). Nadmiar → kwasica ketonowa (DKA w cukrzycy typu 1).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synteza kwasów tłuszczowych (lipogeneza)', 'Cytosol. Acetylo-CoA → malonylo-CoA (karboksylaza acetylo-CoA — enzym regulatorowy, aktywowana przez cytrynian, insulinę; hamowana przez palmitoilo-CoA, glukagon). Syntaza kwasów tłuszczowych (FAS): wieloenzymatyczny kompleks, dodaje po 2C. Produkt: palmitynian (C16). Wymaga NADPH (z PPP i enzymu jabłczanowego).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synteza cholesterolu — regulacja', 'Wątroba, cytosol/ER. Acetylo-CoA → HMG-CoA → mewalonowy → skwalen → cholesterol. Enzym regulatorowy: reduktaza HMG-CoA (cel statyn). Cholesterol hamuje reduktazę (feedback ujemny) i obniża ekspresję receptorów LDL (SREBP). Insulina aktywuje syntezę, glukagon hamuje. Cholesterol: membrany, hormony steroidowe, kwasy żółciowe, witamina D.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lipoproteiny — podział i funkcje', 'Chylomikrony: transport tłuszczów pokarmowych z jelita. VLDL: transport triacylogliceroli z wątroby. IDL → LDL: transport cholesterolu do tkanek („zły cholesterol" — miażdżyca). HDL: transport zwrotny cholesterolu do wątroby („dobry cholesterol"). ApoB-100: LDL. ApoB-48: chylomikrony. ApoE: wychwyt remnantów.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl mocznikowy — przegląd', 'Lokalizacja: wątroba (mitochondria + cytosol). NH₃ + CO₂ → karbamoilofosforan (CPS-I, mitochondrium, wymaga NAG) → cytrulina → argininobursztynian → arginina → mocznik + ornityna. Bilans: 3 ATP/cykl. Mocznik wydalany przez nerki. Defekty cyklu → hiperamonemia → encefalopatia (NH₃ toksyczny dla OUN).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hiperamonemia — patofizjologia', 'NH₃ przenika BBB → astrocyty: glutaminian + NH₃ → glutamina (syntetaza glutaminowa) → obrzęk astrocytów (osmotyczny) → obrzęk mózgu. NH₃ wyczerpuje α-ketoglutaran z cyklu Krebsa → deficyt energetyczny neuronów. Objawy: dezorientacja, asterixis, śpiączka. Leczenie: laktuloza (eliminacja NH₃ przez jelita), ryfaksymina, benzoesany.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aminokwasy glukogenne i ketogenne', 'Glukogenne: szkielet węglowy → pirogronian lub intermedia cyklu Krebsa → glukoneogeneza. Większość aminokwasów. Ketogenne: szkielet → acetylo-CoA lub acetoacetylo-CoA → ciała ketonowe/kwasy tłuszczowe. Wyłącznie ketogenne: leucyna i lizyna. Zarówno gluko- jak i ketogenne: izoleucyna, fenyloalanina, tryptofan, treonina, tyrozyna.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aminokwasy egzogenne (niezbędne)', 'Nie mogą być syntetyzowane de novo przez organizm. Mnemotechnika: PVT TIM HALL — fenyloalanina (Phe), walina (Val), treonina (Thr), tryptofan (Trp), izoleucyna (Ile), metionina (Met), histydyna (His), arginina (Arg — warunkowo), leucyna (Leu), lizyna (Lys). Niedobory prowadzą do ujemnego bilansu azotowego.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fenyloketonuria (PKU)', 'Autosomalny recesywny niedobór hydroksylazy fenyloalaninowej (fenyloalanina → tyrozyna) lub kofaktora BH4. Nagromadzenie Phe → upośledzenie umysłowe, jasna karnacja (brak melaniny — tyrozyna jest prekursorem), mysi zapach (fenylooctan). Leczenie: dieta niskofenyloalaninowa od urodzenia. Screening noworodków obowiązkowy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina B1 (tiamina) — rola metaboliczna', 'Tiamina (koenzym TPP) jest kofaktorem: dehydrogenazy pirogronianowej (PDH), dehydrogenazy α-ketoglutaranowej (cykl Krebsa), transketolazy (szlak pentozofosforanowy), dehydrogenazy α-ketokwasów rozgałęzionych. Niedobór: beri-beri (mokra — niewydolność serca; sucha — neuropatia), encefalopatia Wernickego (alkoholizm).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina B3 (niacyna/NAD⁺) — rola metaboliczna', 'Niacyna (nikotynamid) tworzy NAD⁺ i NADP⁺ — koenzymy reakcji redox. NAD⁺: katabolizm (glikoliza, cykl Krebsa, β-oksydacja). NADPH: anabolizm (synteza kwasów tłuszczowych, ochrona antyoksydacyjna). Niedobór: pelagra (3D — dermatitis, diarrhea, dementia). Syntetyzowana z tryptofanu.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina B12 (kobalamina) — rola i niedobór', 'Kofaktor: syntazy metioninowej (homocysteina → metionina, wymaga też folianu) i mutazy metylomalonylo-CoA (metylomalonylo-CoA → sukcynylo-CoA). Niedobór: anemia megaloblastyczna + objawy neurologiczne (degeneracja powrózków tylnych i bocznych). Przyczyny: anemia złośliwa (brak IF), weganizm. Kwas metylomalnonowy podwyższony.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwas foliowy — rola metaboliczna', 'THF (tetrahydrofolian) przenosi jedności jednowęglowe (metyl, metylen, formyl). Niezbędny do syntezy nukleotydów (dTMP — tymidylanu, puryn) i konwersji homocysteiny → metionina. Niedobór: anemia megaloblastyczna (BEZ objawów neurologicznych — różnica od B12). W ciąży: suplementacja zapobiega wadom cewy nerwowej.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Insulina — mechanizm działania', 'Insulina → receptor (kinaza tyrozynowa) → autofosforylacja → IRS → PI3K → Akt/PKB. Efekty: translokacja GLUT4 (wychwyt glukozy — mięśnie, tkanka tłuszczowa), aktywacja glikogenosyntetazy, aktywacja PFK-2, synteza białek, lipogeneza. Hamowanie: glukoneogenezy, glikogenolizy, lipolizy, ketogenezy. Hormon anaboliczny.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glukagon — mechanizm działania', 'Glukagon (komórki α trzustki) → receptor sprzężony z Gs → cAMP → PKA. Efekty w wątrobie: aktywacja fosforylazy glikogenowej (glikogenoliza), aktywacja glukoneogenezy (PEPCK, F-1,6-BPaza), aktywacja β-oksydacji i ketogenezy. Hamowanie glikolizy (inaktywacja PFK-2) i lipogenezy. Glukagon działa głównie na wątrobę. Hormon kataboliczny.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cukrzyca typu 1 vs typu 2', 'Typ 1: autoimmunologiczne zniszczenie komórek β → brak insuliny. Młodzi pacjenci, szczupli. Skłonność do kwasicy ketonowej (DKA). Leczenie: insulina. Typ 2: insulinooporność + postępujący defekt sekrecji. Starsi, otyli. Zespół metaboliczny. Hiperglikemia hiperosmolarna (HHS). Leczenie: zmiana stylu życia, metformina, inne leki.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwasica ketonowa cukrzycowa (DKA)', 'Brak insuliny → niekontrolowana lipoliza → nadmiar acetylo-CoA → ketogeneza → acetooctan, β-hydroksymaślan → kwasica metaboliczna z luką anionową. Objawy: oddech Kussmaula, zapach acetonu, odwodnienie, bóle brzucha, nudności. Gazometria: pH < 7,3, HCO₃⁻ < 18. Leczenie: płyny, insulina i.v., suplementacja K⁺.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemoglobina glikowana (HbA1c)', 'HbA1c to hemoglobina z nieenzymatycznie przyłączoną glukozą do łańcucha β. Odzwierciedla średnią glikemię z ostatnich 2–3 miesięcy (czas życia erytrocytu ~120 dni). Norma < 5,7%. Prediabetes: 5,7–6,4%. Cukrzyca: ≥ 6,5%. Cel terapeutyczny u większości diabetyków: < 7%. Wynik fałszywie niski w hemolizie, krwawieniu.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Transkrypcja — etapy u eukariontów', 'Inicjacja: czynniki transkrypcyjne (TFIID → TATA box) + polimeraza RNA II. Elongacja: synteza pre-mRNA 5''→3''. Terminacja: sygnał poliadenylacji. Modyfikacje potranslacyjne: czapeczka 5'' (7-metyloguanozyna), ogon poli-A 3'', splicing (usuwanie intronów przez spliceosom). Mutacje splicingowe mogą powodować choroby genetyczne.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Translacja — etapy', 'Inicjacja: mała podjednostka rybosomu + mRNA + tRNA-Met (kodon AUG). Elongacja: aminoacylo-tRNA wchodzi do miejsca A → wiązanie peptydowe (peptydylotransferaza — rRNA) → translokacja (EF-G/eEF2). Terminacja: kodon stop (UAA, UAG, UGA) → czynnik uwalniający. Antybiotyki: aminoglikozydy (30S), makrolidy/chloramfenikol (50S), tetracykliny (30S).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kod genetyczny — cechy', 'Trójkowy: 3 nukleotydy = 1 kodon. Zdegenerowany: wiele kodonów dla jednego aminokwasu (64 kodony, 20 aminokwasów). Uniwersalny (z wyjątkami: mitochondria). Jednoznaczny: 1 kodon = 1 aminokwas. Nieprzekrywający się. Kodon inicjacyjny: AUG (Met). Kodony stop: UAA, UAG, UGA. Wobble: tolerancja w trzeciej pozycji kodonu.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mutacje punktowe — typy i skutki', 'Ciche (silent): zmiana kodonu, ten sam aminokwas (degeneracja kodu). Zmiany sensu (missense): inny aminokwas (np. sierpowatokrwinkowość: GAG→GUG, Glu→Val w β-globinie). Nonsensowna: kodon stop → skrócone białko. Przesunięcie ramki odczytu (frameshift): insercja/delecja nie będąca wielokrotnością 3 → zmiana całej sekwencji downstream.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Naprawa DNA — mechanizmy', 'Naprawa wycinająca nukleotydy (NER): usuwanie dimerów tyminy (UV) — defekt → xeroderma pigmentosum. Naprawa wycinająca zasady (BER): usuwanie uszkodzonych zasad (glikozylaza). Naprawa niesparowanych zasad (MMR): korekta błędów replikacji — defekt → zespół Lyncha (HNPCC). Naprawa DSB: rekombinacja homologiczna (BRCA1/2) lub NHEJ.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synteza hemu i porfirie', 'Synteza hemu: sukc-CoA + glicyna → ALA (ALA-syntaza, mitochondrium, kofaktor: B6) → porfobilinogen → uroporfirynogen → koproporfirynogen → protoporfiryna IX + Fe²⁺ → hem. Defekty enzymów → porfirie. Ostra przerywana (ALA-dehydrataza/PBG-deaminaza): bóle brzucha, neuropatia, objawy psychiatryczne. Porfiria skórna: fotowrażliwość.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Degradacja hemu — bilirubina', 'Hem → biliwerdyna (oksygenaza hemowa) → bilirubina niesprzężona (pośrednia, nierozpuszczalna, wiązana z albuminą) → wątroba: sprzężenie z glukuronianem (UDP-glukuronylotransferaza) → bilirubina sprzężona (bezpośrednia) → żółć → jelito → urobilinogen → sterkobilina (kał) / urobilina (mocz). Żółtaczka: przeszkodowa, miąższowa, hemolityczna.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metabolizm żelaza', 'Wchłanianie w dwunastnicy (Fe²⁺ via DMT1). Transport: transferyna (Fe³⁺). Magazynowanie: ferrytyna (wewnątrzkomórkowa), hemosyderyna (nadmiar). Regulacja: hepcydyna (wątroba) — hamuje ferroportynę → zmniejsza wchłanianie i uwalnianie Fe. Niedobór Fe: anemia mikrocytarna. Nadmiar (hemochromatoza): uszkodzenie wątroby, serca, trzustki.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina D — metabolizm i funkcje', 'Skóra: 7-dehydrocholesterol + UV → cholekalcyferol (D3). Wątroba: 25-hydroksylacja → 25(OH)D (kalcydiol — marker poziomu). Nerki: 1α-hydroksylacja → 1,25(OH)₂D (kalcytriol — aktywna forma). Funkcje: wchłanianie Ca²⁺ i PO₄³⁻ z jelita, mineralizacja kości. Niedobór: krzywica (dzieci), osteomalacja (dorośli).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina K — funkcja i znaczenie kliniczne', 'Witamina K jest kofaktorem γ-karboksylazy glutaminianu — niezbędna do aktywacji czynników krzepnięcia II, VII, IX, X oraz białek C i S. γ-karboksylacja umożliwia wiązanie Ca²⁺. Warfaryna hamuje reduktazę epoksydu witaminy K. Niedobór: koagulopatia. Noworodki: profilaktycznie podaje się wit. K (zapobieganie VKDB).', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina C (kwas askorbinowy) — funkcja', 'Kofaktor hydroksylazy prolinowej i lizylowej (synteza kolagenu). Antyoksydant (regeneracja witaminy E). Ułatwia wchłanianie żelaza (redukcja Fe³⁺ → Fe²⁺). Niezbędna w syntezie karnityny, katecholamin, kwasów żółciowych. Niedobór: szkorbut — krwawienie z dziąseł, wybroczyny, upośledzenie gojenia ran, rozluźnienie zębów.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Koenzym A (CoA) — rola', 'Składnik: kwas pantotenowy (witamina B5) + cysteamina + ADP. Grupa tiolowa (-SH) tworzy wysokoenergetyczne wiązania tioesterowe z grupami acylowymi. Acetylo-CoA: centralny metabolit łączący glikolizę, β-oksydację, cykl Krebsa, ketogenezę, syntezę cholesterolu i kwasów tłuszczowych. CoA jest niezbędny w ~100 reakcjach enzymatycznych.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stres oksydacyjny — wolne rodniki i obrona', 'ROS: anion ponadtlenkowy (O₂⁻), nadtlenek wodoru (H₂O₂), rodnik hydroksylowy (OH•). Źródła: łańcuch oddechowy, NADPH oksydaza. Obrona: dysmutaza ponadtlenkowa (SOD: O₂⁻ → H₂O₂), katalaza i peroksydaza glutationowa (H₂O₂ → H₂O). Glutation (GSH) — główny antyoksydant wewnątrzkomórkowy, regenerowany przez reduktazę glutationową (NADPH).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl alaninowo-glukozowy', 'Mięśnie: transaminacja pirogronianu + aminokwasy → alanina → krew → wątroba → transaminacja → pirogronian → glukoneogeneza → glukoza → mięśnie. Równocześnie NH₂ z mięśni transportowany do wątroby jako alanina (bezpieczny nośnik azotu). W wątrobie NH₃ wchodzi do cyklu mocznikowego.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reakcje transaminacji', 'Transaminazy (aminotransferazy) przenoszą grupę aminową z aminokwasu na α-ketokwas. Koenzym: fosforan pirydoksalu (PLP, witamina B6). ALT: alanina + α-ketoglutaran ⇌ pirogronian + glutaminian (marker wątroby). AST: asparaginian + α-ketoglutaran ⇌ oksalooctan + glutaminian (wątroba, serce, mięśnie). Podwyższone w uszkodzeniu hepatocytów.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kinetyka enzymatyczna — Michaelis-Menten', 'v = Vmax × [S] / (Km + [S]). Km = stężenie substratu przy v = Vmax/2. Niskie Km = wysokie powinowactwo. Vmax zależy od stężenia enzymu. Inhibicja kompetycyjna: zwiększa Km (pozorne), Vmax bez zmian. Inhibicja niekompetycyjna: Km bez zmian, Vmax zmniejszone. Wykres Lineweavera-Burka: 1/v vs 1/[S].', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Regulacja allosteryczna enzymów', 'Enzymy allosteryczne mają kinetykę sigmoidalną (nie Michaelis-Menten). Efektory wiążą się w miejscu allosterycznym (nie aktywnym). Aktywatory obniżają K0,5 (pozorny Km), inhibitory podwyższają. Przykłady: PFK-1 (aktywator: AMP, F-2,6-BP; inhibitor: ATP, cytrynian). Regulacja allosteryczna zapewnia szybką odpowiedź na zmiany metaboliczne.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Nabłonek jednowarstwowy płaski — lokalizacja i funkcja', 'Pojedyncza warstwa spłaszczonych komórek na błonie podstawnej. Lokalizacja: śródbłonek naczyń, mezotelium (opłucna, otrzewna, osierdzie), pęcherzyki płucne, pętla Henlego, torebka Bowmana. Funkcja: ułatwia dyfuzję gazów, filtrację, transport płynów. Bardzo cienki — nie chroni mechanicznie.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek jednowarstwowy sześcienny — lokalizacja', 'Komórki sześcienne (kwadratowe w przekroju) na błonie podstawnej. Lokalizacja: cewki nerkowe (proksymalne i dystalne), tarczyca (pęcherzyki), powierzchnia jajnika, przewody wydzielnicze gruczołów. Funkcja: wydzielanie i wchłanianie. Nabłonek cewek proksymalnych ma rąbek szczoteczkowy zwiększający powierzchnię.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek jednowarstwowy walcowaty — typy i lokalizacja', 'Komórki kolumnowe (wyższe niż szerokie). Bez rzęsek: żołądek, jelita (komórki kubkowe produkujące śluz, enterocyty z mikrokosmkami). Z rzęskami: jajowody (transport komórki jajowej), drogi oddechowe (oczyszczanie śluzowo-rzęskowe). Funkcja: wchłanianie, wydzielanie, ochrona.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek wielorzędowy — cechy i lokalizacja', 'Pseudostratified — wszystkie komórki dotykają błony podstawnej, ale nie wszystkie sięgają powierzchni. Jądra na różnych wysokościach → wrażenie wielu warstw. Lokalizacja: drogi oddechowe (z rzęskami i komórkami kubkowymi), najądrze, przewody wyprowadzające ucha. Oczyszczanie śluzowo-rzęskowe.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek wielowarstwowy płaski rogowaciejący', 'Wiele warstw komórek, warstwa powierzchniowa — martwe, zrogowaciałe (keratyna). Lokalizacja: skóra (naskórek). Najgrubszy nabłonek. Funkcja: ochrona mechaniczna, bariera przed utratą wody i mikroorganizmami. Warstwy naskórka: podstawna, kolczysta, ziarnista, jasna (dłonie/stopy), rogowa.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek wielowarstwowy płaski nierogowaciejący', 'Wiele warstw, warstwa powierzchniowa — żywe, nierogowaciejące komórki. Lokalizacja: jama ustna, gardło, przełyk, pochwa, rogówka, kanał odbytu. Funkcja: ochrona mechaniczna w wilgotnych środowiskach. W przełyku może ulegać metaplazji do nabłonka walcowatego (przełyk Barretta) pod wpływem refluksu.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek przejściowy (urotelium)', 'Specjalny nabłonek wielowarstwowy dróg moczowych. Komórki powierzchniowe — „parasole" (umbrella cells, białko uroplakin). Zmienia grubość: rozciągnięty (2–3 warstwy) vs pusty pęcherz (5–6 warstw). Lokalizacja: miedniczka nerkowa, moczowód, pęcherz moczowy. Bariera dla moczu (nieprzepuszczalny).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Błona podstawna — budowa i funkcje', 'Warstwa pozakomórkowa pod nabłonkiem. Budowa: lamina lucida, lamina densa (kolagen IV, laminina, proteoglikany), lamina reticularis (kolagen III). Funkcje: zakotwiczenie nabłonka, filtracja (kłębuszek nerkowy), bariera dla komórek nowotworowych (naciekanie = przełamanie błony). Przeciwciała anty-błonie podstawnej → zespół Goodpasture''a.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Złącza ścisłe (tight junctions / zonula occludens)', 'Pasmo białek (klaudyny, okludyny) otaczające szczyt komórki nabłonkowej. Funkcja: bariera paracelularna — kontrola przepuszczalności między komórkami, zapobieganie mieszaniu się białek apikalnych i bazolateralnych (polarność). Najsilniejsze w BBB i nabłonku pęcherza moczowego. Osłabienie → przecieki, obrzęk.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Desmosomy (macula adherens)', 'Punktowe połączenia mechaniczne między komórkami. Białka: kadheryny desmosomalne (desmogleina, desmocolina) zakotwiczone w plakoglobinie → filament pośredni keratynowy. Liczne w nabłonku narażonym na stres mechaniczny (naskórek, mięsień sercowy). Pęcherzyca zwykła: autoprzeciwciała anty-desmogleina → oddzielanie naskórka → pęcherze.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Złącza szczelinowe (gap junctions)', 'Kanały (koneksony = 6 koneksyn) łączące cytoplazmę sąsiednich komórek. Przepuszczają jony i małe cząsteczki (< 1 kDa). Funkcja: komunikacja elektryczna i metaboliczna. Kluczowe w: mięśniu sercowym (synchroniczny skurcz), mięśniu gładkim, hepatocytach, astrocytach. Mutacje koneksyny 26 → głuchota dziedziczna.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gruczoły egzokrynne — klasyfikacja wg wydzieliny', 'Surowicze (serozne): cienka, wodnista wydzielina bogata w enzymy. Ciemne jądra, wąskie światło (np. przyusznica, trzustka egzokrynna). Śluzowe: gęsty śluz (mucyny). Jasna cytoplazma, spłaszczone jądra przy podstawie (np. podniebienne). Mieszane (seromukozne): oba typy, surowicze półksiężyce Giannuzziego (np. podżuchwowa).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gruczoły — mechanizmy wydzielania', 'Merokrynowe: egzocytoza bez utraty cytoplazmy (większość gruczołów — ślinianki, trzustka, gruczoły potowe ekrynowe). Apokrynowe: odcinanie szczytowej części cytoplazmy z wydzieliną (gruczoły mlekowe, gruczoły potowe apokrynowe — pachy). Holokrynowe: cała komórka rozpada się stając się wydzieliną (gruczoły łojowe).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka łączna właściwa wiotka (luźna)', 'Więcej substancji podstawowej niż włókien. Zawiera kolagen I i III, włókna sprężyste, fibroblasty, makrofagi, komórki tuczne, adipocyty. Lokalizacja: pod nabłonkami (lamina propria), wokół naczyń i nerwów, podskórna. Funkcja: wypełnienie, obrona immunologiczna, odżywianie nabłonka.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka łączna właściwa zbita — regularna i nieregularna', 'Zbita regularna: równoległe wiązki kolagenu I → duża wytrzymałość w jednym kierunku. Lokalizacja: ścięgna, więzadła, rozcięgna. Zbita nieregularna: wiązki kolagenu w różnych kierunkach → wytrzymałość wielokierunkowa. Lokalizacja: skóra właściwa (dermis), okostna, torebki narządów, zastawki serca.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolagen — typy i znaczenie kliniczne', 'Typ I: kości, ścięgna, skóra, rogówka (90% kolagenu). Typ II: chrząstka szklista i sprężysta. Typ III: siatkowy — naczynia, narządy, razem z I. Typ IV: błona podstawna (sieć, nie włókna). Synteza wymaga wit. C (hydroksylacja Pro/Lys). Osteogenesis imperfecta: defekt kolagenu I → łamliwość kości. Zespół Ehlersa-Danlosa: hiperelastyczność.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Włókna sprężyste (elastyna)', 'Elastyna + fibrylina → włókna sprężyste. Rozciągliwe i powracające do kształtu. Lokalizacja: ściana aorty, więzadła żółte, płuca, skóra, chrząstka sprężysta. Zespół Marfana: defekt fibryliny-1 → tętniak aorty, podwichnięcie soczewki, wysoki wzrost, arachnodaktylia. Rozedma płuc: zniszczenie elastyny (elastaza neutrofilów, niedobór α1-antytrypsyny).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fibroblasty — funkcje', 'Główne komórki tkanki łącznej. Syntetyzują składniki macierzy pozakomórkowej: kolagen, elastynę, proteoglikany, glikozaminoglikany, fibronektynę. Aktywne fibroblasty: obfite RER, jasne jądro. Nieaktywne (fibrocyty): wrzecionowate, ciemne jądro. Miofibroblasty (aktyna α-gładkomięśniowa): obkurczanie ran.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Makrofagi tkankowe — nazwy w różnych narządach', 'Makrofagi pochodzą z monocytów krwi. Nazwy lokalne: komórki Kupffera (wątroba), makrofagi pęcherzykowe (płuca — „komórki kurzu"), mikroglej (OUN), osteoklasty (kość), komórki Langerhansa (naskórek — komórki dendrytyczne). Funkcje: fagocytoza, prezentacja antygenów (APC), wydzielanie cytokin (IL-1, TNF-α, IL-6).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki tuczne (mastocyty)', 'Duże komórki z licznymi ziarnistościami metachromatycznymi (toluidyna — czerwono-fioletowe). Zawierają histaminę, heparynę, tryptazę, leukotrieny, cytokiny. Receptor FcεRI wiąże IgE. Degranulacja po kontakcie alergenu z IgE → reakcja anafilaktyczna (typ I). Lokalizacja: tkanka łączna skóry, drogi oddechowe, przewód pokarmowy.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka tłuszczowa biała vs brązowa', 'Biała: jednolokularna (jedna duża kropla tłuszczu), spłaszczone jądro na obwodzie. Funkcje: magazynowanie energii, izolacja termiczna, ochrona mechaniczna, funkcja endokrynna (leptyna, adiponektyna). Brązowa: wielolokularna (wiele kropli), liczne mitochondria (kolor), UCP1 (termogenina). Funkcja: termogeneza bezdrżeniowa. U noworodków i w małych ilościach u dorosłych.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chrząstka szklista (hyalinowa)', 'Najczęstszy typ chrząstki. Kolagen II, proteoglikany (agrekan), chondrocyty w lakunach. Przezroczysto-niebieska, szklista. Lokalizacja: powierzchnie stawowe, chrząstki żebrowe, nos, krtań, tchawica (pierścienie C), oskrzela. Brak naczyń krwionośnych — odżywiana dyfuzją z ochrzęstnej. Regeneracja ograniczona.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chrząstka sprężysta', 'Podobna do szklistej + dodatkowo włókna sprężyste (elastyna) → większa elastyczność. Żółtawa barwa. Lokalizacja: małżowina uszna, nagłośnia, przewód słuchowy zewnętrzny, chrząstki krtani (rożkowata, klinowata). Otoczona ochrzęstną. Nie ulega wapnieniu (w odróżnieniu od chrząstki szklistej).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chrząstka włóknista', 'Dużo kolagenu I (wiązki widoczne w preparacie) + mniejsze ilości kolagenu II. Brak ochrzęstnej. Chondrocyty w rzędach między wiązkami kolagenu. Łączy cechy chrząstki i tkanki łącznej zbitej. Lokalizacja: dyski międzykręgowe (pierścień włóknisty), łąkotki kolana, spojenie łonowe, przyczepy ścięgien. Wytrzymałość na ściskanie i rozciąganie.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kość zbita (korowa) — budowa', 'Jednostka strukturalna: osteon (system Haversa). Centralny kanał Haversa (naczynia, nerwy) otoczony koncentrycznymi lamelami kostnymi z osteocytami w lakunach, połączonymi kanalikikami. Kanały Volkmanna łączą osteony ze sobą i z okostną. Okostna: warstwa włóknista (kolagen) i osteogenna (osteoblasty). Stanowi ~80% masy szkieletu.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kość gąbczasta (beleczkowa)', 'Sieć beleczek (trabekul) kostnych otaczających szpik. Brak osteonów — osteocyty odżywiane dyfuzją z naczyń szpiku. Lokalizacja: nasady kości długich, trzony kręgów, kości płaskie (diploe). Powierzchnia wewnętrzna: śródkostna (endosteum — osteoblasty, osteoklasty). Osteoporoza dotyka głównie kości gąbczastej (np. złamania trzonów kręgów).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Osteoblasty, osteocyty, osteoklasty', 'Osteoblasty: syntetyzują osteoid (kolagen I + proteoglikany), mineralizacja (hydroksyapatyt). Markery: fosfataza alkaliczna, osteokalcyna. Osteocyty: dojrzałe osteoblasty zamurowane w lakunach, połączone kanalikikami — mechanosensory. Osteoklasty: duże, wielojądrowe (z monocytów), resorpcja kości (kwas + TRAP + katepsyna K). Ruffled border, Howshippy''s lacunae.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kostnienie wewnątrzbłonowe vs chrzęstne', 'Wewnątrzbłonowe (desmalne): bezpośrednio z mezenchymu (bez chrząstki). Kości płaskie czaszki, obojczyk. Osteoblasty różnicują się z mezenchymu → osteoid → mineralizacja. Chrzęstne (endochondralne): model chrząstkowy zastępowany kością. Kości długie, kręgosłup, miednica. Płytka wzrostowa: strefy spoczynku, proliferacji, hipertrofii, mineralizacji, kostnienia.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka mięśniowa szkieletowa — cechy histologiczne', 'Włókna wielojądrowe (syncytium), jądra obwodowe (pod sarkolemmą). Prążkowanie poprzeczne (sarkomery). Sarkomer: od linii Z do Z. Pasmo A (anizotropowe — ciemne, miozynowe). Pasmo I (izotropowe — jasne, aktynowe). Strefa H (tylko miozyna). Linia M (środek sarkomeru). Podczas skurczu: I i H skracają się, A nie zmienia długości.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mechanizm skurczu mięśnia szkieletowego', 'PA → cewka T → receptor DHP → aktywacja receptora rianodynowego (RyR1) na SR → uwalnianie Ca²⁺ → Ca²⁺ wiąże troponinę C → zmiana konformacji tropomiozyny → odsłonięcie miejsc aktywnych aktyny → mostek krzyżowy miozyny → cykl mostu (ATP-zależny) → skurcz. Rozkurcz: Ca²⁺ pompowane z powrotem do SR przez SERCA.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Typy włókien mięśniowych szkieletowych', 'Typ I (wolne, czerwone): dużo mitochondriów i mioglobiny, metabolizm tlenowy, odporne na zmęczenie. Mięśnie posturalne. Typ IIa (szybkie oksydacyjno-glikolityczne): pośrednie. Typ IIb (szybkie glikolityczne, białe): mało mitochondriów, szybko się męczą, duża siła. Sprinterzy. Proporcje zależne od treningu i genetyki.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka mięśniowa sercowa — cechy histologiczne', 'Komórki rozgałęzione, jedno centralne jądro (czasem dwa). Prążkowanie jak w szkieletowej. Krążki wstawkowe (intercalated discs): desmosomy (połączenie mechaniczne) + gap junctions (połączenie elektryczne — syncytium czynnościowe). Dysmorfologia serca: brak regeneracji — zastępowanie blizną po zawale. Liczne mitochondria (~40% objętości).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sprzężenie elektromechaniczne w mięśniu sercowym', 'PA → cewka T → receptor DHP (kanał Ca²⁺ typu L) → napływ Ca²⁺ z zewnątrz → aktywacja RyR2 na SR → uwolnienie Ca²⁺ z SR (CICR — calcium-induced calcium release). Ca²⁺ → troponina C → skurcz. Rozkurcz: SERCA (SR), wymiennik Na⁺/Ca²⁺ (sarkolemma). Digoksyna: hamuje Na⁺/K⁺-ATPazę → więcej Ca²⁺ → silniejszy skurcz.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka mięśniowa gładka — cechy', 'Komórki wrzecionowate, jedno centralne jądro, brak prążkowania (brak sarkomerów — aktyna i miozyna w sieciach). Skurcz: Ca²⁺ → kalmodulina → kinaza lekkiego łańcucha miozyny (MLCK) → fosforylacja miozyny → mostek krzyżowy. Wolny, toniczny skurcz. Lokalizacja: ściany naczyń, przewód pokarmowy, drogi moczowe, macica, tęczówka.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Różnice między mięśniem szkieletowym, sercowym i gładkim', 'Szkieletowy: wielojądrowy, dowolny, szybki, brak gap junctions. Sercowy: 1–2 jądra, mimowolny, gap junctions (krążki wstawkowe), CICR, automatyzm. Gładki: 1 jądro, mimowolny, brak prążkowania, MLCK-zależny, powolny, gap junctions (niektóre), plastyczność skurczu. Regeneracja: gładki > sercowy (minimalna) ≈ szkieletowy (komórki satelitarne).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Neuron — budowa', 'Ciało komórkowe (perikarion): jądro, substancja Nissla (RER), aparat Golgiego. Dendryty: liczne, rozgałęzione, odbierają sygnały. Akson: jeden, długi, przewodzi PA od wzgórka aksonu. Osłona mielinowa (komórki Schwanna/oligodendrocyty). Synapsa: zakończenie presynaptyczne (pęcherzyki), szczelina, membrana postsynaptyczna.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Klasyfikacja neuronów wg budowy', 'Wielobiegunowe: jeden akson, wiele dendrytów — większość neuronów OUN, neurony ruchowe. Dwubiegunowe: jeden akson, jeden dendryt — siatkówka, nabłonek węchowy, zwój przedsionkowo-ślimakowy. Pseudojednobiegunowe: jeden wyrostek dzielący się na T — zwoje rdzeniowe (czuciowe). Klinicznie: neuropatie dotyczą najdłuższych aksonów (polineuropatia dystalna).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Astrocyty — funkcje szczegółowe', 'Protoplazmatyczne (istota szara) i włókniste (istota biała). Funkcje: 1) BBB (stopki naczyniowe). 2) Wychwyt glutaminianu i K⁺ (zapobieganie ekscytotoksyczności). 3) Metabolizm glikogenu (rezerwowy substrat energetyczny). 4) Blizna glejowa po uszkodzeniu (glioza). 5) Regulacja synaptogenezy. GFAP — marker immunohistochemiczny astrocytów.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Oligodendrocyty vs komórki Schwanna', 'Oligodendrocyty: OUN, jeden oligodendrocyt mielinizuje fragmenty wielu aksonów (do 50). Komórki Schwanna: obwodowy UN, jedna komórka mielinizuje jeden segment jednego aksonu. Regeneracja nerwu obwodowego możliwa (komórki Schwanna tworzą tunel Büngera). W OUN regeneracja utrudniona (inhibicja przez Nogo, MAG).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mikroglej — funkcje', 'Komórki rezydentne pochodzenia mezenchymalnego (szpikowego), nie neuroektodermalnego. Makrofagi OUN. Funkcje: nadzór immunologiczny, fagocytoza szczątków komórkowych i patogenów, prezentacja antygenów, wydzielanie cytokin (TNF-α, IL-1β). Aktywacja w stanach zapalnych, udarze, chorobach neurodegeneracyjnych. Nadmierna aktywacja → neurotoksyczność.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki wyściółki (ependymocyty)', 'Jednowarstwowe komórki walcowate/sześcienne wyściełające komory mózgu i kanał centralny rdzenia. Rzęski — ruch CSF. W splotach naczyniówkowych: modyfikowane ependymocyty produkujące CSF (ultrafiltracja osocza + aktywny transport). Tanycyty: wyspecjalizowane ependymocyty w III komorze — chemosensory (glukoza, hormony).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemidesmosomy', 'Łączą podstawę komórek nabłonkowych z błoną podstawną (w odróżnieniu od desmosomów łączących komórki ze sobą). Białka: integryna α6β4, kolagen XVII (BP180), plektyna → filament keratynowy. Pemfigoid pęcherzowy: autoprzeciwciała anty-BP180/BP230 → oddzielenie naskórka od błony podstawnej → pęcherze podskórne (napięte, w odróżnieniu od wiotkich w pęcherzycy).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Substancja podstawna tkanki łącznej', 'Galaretowata, amorficzna matryca między komórkami i włóknami. Składniki: glikozaminoglikany (GAG: hialuronian, chondroitynosiarczan, heparanosiarczan, keratanosiarczan), proteoglikany (GAG + białko rdzeniowe, np. agrekan). Funkcje: uwodnienie, sprężystość, odporność na ściskanie, filtracja, bariera dyfuzyjna. Mukopolisacharydozy: brak enzymów degradujących GAG.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metaplazja — definicja i przykłady', 'Metaplazja to odwracalna przemiana jednego typu dojrzałej tkanki w inny. Reakcja adaptacyjna na chroniczne podrażnienie. Przykłady: nabłonek dróg oddechowych (wielorzędowy rzęskowy → wielowarstwowy płaski u palaczy), przełyk Barretta (wielowarstwowy płaski → walcowaty z komórkami kubkowymi — refluks). Metaplazja zwiększa ryzyko dysplazji i nowotworu.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki satelitarne mięśni szkieletowych', 'Komórki macierzyste mięśniowe leżące między sarkolemmą a błoną podstawną włókna mięśniowego. W odpowiedzi na uszkodzenie aktywują się, proliferują i łączą z uszkodzonym włóknem lub tworzą nowe. Odpowiadają za regenerację mięśnia szkieletowego. Z wiekiem ich liczba maleje → zmniejszona zdolność regeneracyjna. Marker: Pax7.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka łączna siateczkowata', 'Delikatna sieć włókien retikulinowych (kolagen III) z komórkami siateczkowatymi. Tworzy zrąb narządów limfatycznych (węzły chłonne, śledziona, szpik kostny), wątroby, nerek. Barwienie: impregnacja srebrem (PAS+). Fibroza: włókna retikulinowe mogą być zastępowane kolagene I (marskość wątroby).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Naczynia włosowate (kapilary) — typy', 'Ciągłe: śródbłonek ciągły + błona podstawna ciągła. Mięśnie, płuca, OUN. Okienkowe (fenestrowane): okienka (fenestry) z diafragmą. Kłębuszki nerkowe, jelita, gruczoły dokrewne. Sinusoidalne: duże, nieregularne, z przerwami w śródbłonku i błonie podstawnej. Wątroba, śledziona, szpik. Pozwalają na przejście komórek krwi i dużych białek.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pneumocyty typu I i II', 'Typ I: płaskie, pokrywają ~95% powierzchni pęcherzyków. Cienkie → ułatwiają wymianę gazową. Nie dzielą się. Typ II: sześcienne, ~5% powierzchni, ale ~60% komórek pęcherzykowych. Produkują surfaktant (ciałka blaszkowate). Komórki macierzyste pęcherzyka — regenerują typ I i II po uszkodzeniu.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Barwienie H&E — co pokazuje', 'Hematoksylina (zasadowa, niebiesko-fioletowa): barwi kwasy nukleinowe (jądra), rybosomy, RER. Eozyna (kwaśna, różowa): barwi białka cytoplazmatyczne, kolagen, mięśnie. Podstawowe barwienie histologiczne. Jądro: niebieskie. Cytoplazma: różowa. Kolagen: różowy. Erytrocyty: jasno-czerwone. Mięśnie: intensywnie różowe.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Keratyna i filamenty pośrednie — znaczenie diagnostyczne', 'Filamenty pośrednie (10 nm) są markerami różnicowania tkankowego w immunohistochemii. Cytokeratyny: nabłonek (karcynomy). Wimentyna: mezenchyma (mięsaki). Desmina: mięśnie. GFAP: astrocyty (glejaki). Neurofilamenty: neurony. Pomocne w diagnostyce nowotworów o nieznanym punkcie wyjścia (CUP — cancer of unknown primary).', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Zapalenie ostre — cechy kardynalne', 'Pięć cech zapalenia (Celsus + Virchow): rubor (zaczerwienienie — wazodylatacja), tumor (obrzęk — zwiększona przepuszczalność), calor (ciepło — zwiększony przepływ), dolor (ból — mediatory: bradykinina, prostaglandyny), functio laesa (upośledzenie funkcji). Zapalenie ostre: szybki początek, krótki czas, nacieki neutrofilowe.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie ostre — sekwencja zdarzeń naczyniowych', 'Krótkotrwałe zwężenie naczyń → wazodylatacja (histamina, NO) → spowolnienie przepływu → marginalizacja leukocytów → toczenie się (selektyny E, P) → adhezja (integryny LFA-1 → ICAM-1) → diapedeza (migracja przez ścianę naczynia) → chemotaksja (C5a, LTB4, IL-8) → fagocytoza w ognisku zapalnym.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Histamina — źródło i efekty', 'Źródło: komórki tuczne, bazofile, płytki. Uwalniana przez: IgE (alergia), C3a/C5a (anafilatoksyny), uraz fizyczny. Efekty: wazodylatacja arterioli (H1), zwiększona przepuszczalność żyłek (H1), skurcz oskrzeli (H1), wydzielanie HCl (H2), świąd (H1). Antyhistaminiki H1: loratadyna, cetyryzyna. H2: ranitydyna, famotydyna.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prostaglandyny — rola w zapaleniu', 'Kwas arachidonowy → cyklooksygenaza (COX-1/COX-2) → prostaglandyny. PGE2: ból (sensytyzacja nocyceptorów), gorączka (hipotalamus), wazodylatacja. PGI2 (prostacyklina): wazodylatacja, hamuje agregację płytek. TXA2 (tromboksan, z płytek): wazokonstrykcja, agregacja płytek. NLPZ (ibuprofen, aspiryna) hamują COX → zmniejszenie bólu, gorączki, zapalenia.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leukotrieny — rola w zapaleniu', 'Kwas arachidonowy → 5-lipoksygenaza → leukotrieny. LTB4: silny chemoatraktant neutrofilów. LTC4, LTD4, LTE4 (dawniej SRS-A): skurcz oskrzeli (100× silniejszy niż histamina), zwiększona przepuszczalność naczyń, wydzielanie śluzu. Kluczowe w astmie. Antagoniści receptora leukotrienowego: montelukast.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cytokiny w zapaleniu — TNF-α i IL-1', 'TNF-α i IL-1 (z makrofagów) są kluczowymi cytokinami zapalenia ostrego. Efekty lokalne: aktywacja śródbłonka (selektyny, ICAM), chemotaksja, aktywacja leukocytów. Efekty systemowe: gorączka (PGE2 w hipotalamusie), białka ostrej fazy (CRP, fibrynogen — wątroba), leukocytoza, kacheksja (TNF-α = kachektyna). Anty-TNF (infliksymab): leczenie chorób zapalnych.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ dopełniacza — szlaki aktywacji', 'Klasyczny: kompleks antygen-przeciwciało (IgM, IgG) → C1 → C4, C2. Alternatywny: spontaniczna hydroliza C3 na powierzchni drobnoustrojów → czynnik B, D. Lektynowy: MBL wiąże mannozę drobnoustrojów. Wszystkie → C3-konwertaza → C3a (anafilatoksyna), C3b (opsonizacja) → C5a (chemotaksja, anafilatoksyna) → C5b-9 (MAC — liza komórek).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie ostre — typy wysięku', 'Surowiczy: płyn ubogobiałkowy (oparzenie, zapalenie surowicze). Włóknikowy: bogaty w fibrynogen → fibryna (zapalenie osierdzia, opłucnej). Ropne (gnilne): nagromadzenie neutrofili → ropień (otorbiony) lub ropniak (w jamie ciała). Krwotoczny: uszkodzenie naczyń (meningokoki, nowotwory). Wrzodziejący: martwica nabłonka.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie przewlekłe — cechy', 'Zapalenie trwające tygodnie-lata. Jednoczesna destrukcja i naprawa tkanek. Naciek: makrofagi, limfocyty, plazmocyty (nie neutrofile). Tworzenie ziarniny (angiogeneza + fibroblasty). Włóknienie. Przyczyny: przetrwałe zakażenia (TB, wirusy), choroby autoimmunologiczne, ciała obce. Może być od początku przewlekłe (bez fazy ostrej).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie ziarniniakowe — definicja i przyczyny', 'Ziarniniak: ognisko zorganizowanych makrofagów (komórki nabłonkowate, wielojądrowe komórki olbrzymie Langerhansa). Przyczyny: gruźlica (ziarniniak serowaciejący), sarkoidoza (nieserowaciejący), trąd, kiła, choroba kociego pazura, Crohn, ciała obce (szwy, talk). Ziarniniak gruźliczy: centralna martwica serowata + komórki nabłonkowate + komórki Langerhansa.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gojenie ran — fazy', '1. Hemostaza (sekundy-minuty): skurcz naczyń, agregacja płytek, fibryna. 2. Zapalenie (1–3 dni): neutrofile, potem makrofagi — oczyszczanie. 3. Proliferacja (3–21 dni): angiogeneza, fibroblasty, kolagen, tkanka ziarninowa, naskórkowanie. 4. Przebudowa (tygodnie-lata): dojrzewanie kolagenu (III → I), obkurczanie blizny. Wytrzymałość blizny maks. ~80% normy.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gojenie pierwotne vs wtórne', 'Pierwotne (per primam intentionem): brzegi rany zbliżone (szew), minimalna tkanka ziarninowa, mała blizna. Np. rana chirurgiczna. Wtórne (per secundam intentionem): rana otwarta, duża utrata tkanki, dużo tkanki ziarninowej, obkurczanie (miofibroblasty), duża blizna. Np. owrzodzenie, ropień po drenażu.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czynniki upośledzające gojenie ran', 'Zakażenie (najczęstszy), niedokrwienie i hipoksja, cukrzyca (mikroangiopatia, neuropatia), ciała obce, niedobory żywieniowe (wit. C — kolagen, cynk — proliferacja), glikokortykosteroidy (hamują zapalenie i syntezę kolagenu), wiek zaawansowany, niedożywienie białkowe, napromienianie.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nowotwór łagodny vs złośliwy — cechy', 'Łagodny: dobrze ograniczony (torebka), wolny wzrost, dobrze zróżnicowany, nie daje przerzutów, nazwa: -oma (np. gruczolak, tłuszczak). Złośliwy: naciekanie (brak torebki), szybki wzrost, atypie, przerzuty, martwica, nazwa: -carcinoma (nabłonek), -sarcoma (mezenchyma). Wyjątki w nazewnictwie: chłoniak, czerniak, białaczka — są złośliwe.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dysplazja — definicja i znaczenie', 'Dysplazja to zaburzenie dojrzewania i organizacji komórek nabłonkowych: zwiększona mitotyczna aktywność, atypie jądrowe, utrata polarności, ale bez naciekania błony podstawnej. Stopnie: lekka (CIN I), umiarkowana (CIN II), ciężka (CIN III / carcinoma in situ). Może cofnąć się lub postępować do raka inwazyjnego. Nie jest nowotworem, ale stanem przedrakowym.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przerzuty — drogi szerzenia się nowotworu', 'Szerzenie lokalne: naciekanie (kolagenazy, metaloproteazy). Przerzuty krwiopochodne: mięsaki → żyły → płuca; guzy jelita → żyła wrotna → wątroba. Przerzuty limfogenne: raki → regionalne węzły chłonne (pierwsza stacja). Przeszczep (seeding): jama otrzewnej (rak jajnika, żołądka), CSF (medulloblastoma). Kaskada przerzutowa: odłączenie → inwazja → intravasation → przeżycie → extravasation → kolonizacja.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Grading vs staging nowotworów', 'Grading (stopień złośliwości histologicznej): G1 — dobrze zróżnicowany, G2 — umiarkowanie, G3 — nisko, G4 — niezróżnicowany. Oparty na wyglądzie mikroskopowym (mitotyczność, atypie). Staging (stopień zaawansowania): TNM — T (wielkość guza), N (węzły chłonne), M (przerzuty odległe). Staging ma większe znaczenie rokownicze niż grading.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Onkogeny — definicja i przykłady', 'Protoonkogeny to prawidłowe geny pobudzające wzrost komórkowy. Mutacja „gain of function" → onkogen → konstytutywna aktywacja → proliferacja. Przykłady: RAS (mutacja punktowa, 30% nowotworów), HER2/neu (amplifikacja, rak piersi), MYC (translokacja, chłoniak Burkitta), BCR-ABL (translokacja t(9;22), CML — chromosom Philadelphia). Działanie dominujące — wystarczy 1 zmutowany allel.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Geny supresorowe nowotworu — definicja i przykłady', 'Geny supresorowe hamują proliferację. Mutacja „loss of function" → utrata hamowania → nowotwór. Wymagane mutacje obu alleli (hipoteza dwóch uderzeń Knudsona). Przykłady: TP53 (p53 — „strażnik genomu", kontrola cyklu, apoptoza; zmutowany w >50% raków), RB (retinoblastoma), APC (polipowatość rodzinna, rak jelita grubego), BRCA1/BRCA2 (rak piersi/jajnika).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Białko p53 — funkcje', 'TP53 koduje czynnik transkrypcyjny aktywowany przez uszkodzenie DNA, hipoksję, aktywację onkogenów. Funkcje: 1) Zatrzymanie cyklu komórkowego (G1 — p21 hamuje CDK). 2) Naprawa DNA. 3) Apoptoza (Bax, PUMA). 4) Hamowanie angiogenezy. Mutacja TP53 (zespół Li-Fraumeni): zwiększone ryzyko wielu nowotworów w młodym wieku.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Markery nowotworowe — przykłady', 'PSA: rak prostaty (screening, monitorowanie). CEA: rak jelita grubego (monitorowanie, nie screening). AFP: rak wątrobowokomórkowy, guzy zarodkowe. CA-125: rak jajnika. CA 19-9: rak trzustki. β-hCG: choriocarcinoma, seminoma. Kalcytonina: rak rdzeniasty tarczycy. Markery służą głównie do monitorowania leczenia, nie do rozpoznania.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zespoły paranowotworowe — przykłady', 'Objawy odległe od guza, nie związane z przerzutami. Hiperkalcemia: PTHrP (rak płaskonabłonkowy płuca). SIADH: ADH ektopowe (drobnokomórkowy rak płuca). Cushing: ACTH ektopowe (drobnokomórkowy rak płuca). Czerwienica: erytropoetyna (rak nerki). Zapalenie wielomięśniowe/skórnomięśniowe: rak płuca, jajnika. Acanthosis nigricans: rak żołądka.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Triada Virchowa — zakrzepica', 'Trzy czynniki predysponujące do zakrzepicy: 1) Uszkodzenie śródbłonka (miażdżyca, uraz, zapalenie). 2) Zaburzenia przepływu krwi — zastój (żylna) lub turbulencja (tętnicza). 3) Nadkrzepliwość (trombofilia — czynnik V Leiden, deficyt białka C/S, antytrombiny III, zespół antyfosfolipidowy, nowotwory, OCP). Zakrzepica żylna → PE; tętnicza → zawał, udar.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zatorowość płucna (PE) — patofizjologia', 'Najczęściej zator z zakrzepicy żył głębokich kończyn dolnych (DVT). Zator blokuje tętnice płucne → wzrost oporu płucnego → ostra prawokomorowa niewydolność → spadek rzutu lewej komory → hipotensja. Masywna PE (> 60% łożyska płucnego) → wstrząs obstrukcyjny, nagły zgon. Objawy: duszność, tachykardia, ból opłucnowy, D-dimery↑. Profilaktyka DVT: heparyna, mobilizacja.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Typy zatorów', 'Zakrzepowy (najczęstszy, >95%): z DVT → PE. Tłuszczowy: po złamaniach kości długich → petechie, duszność, splątanie (po 24–72h). Powietrzny: procedury chirurgiczne, cewnikowanie, barotrauma. Płynu owodniowego: podczas porodu, DIC. Cholesterolowy (miażdżycowy): „blue toe syndrome". Nowotworowy: fragmenty guza w naczyniach. Septyczny: zapalenie wsierdzia → ropnie narządowe.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zawał — definicja i typy', 'Zawał = martwica niedokrwienna z powodu okluzji naczynia. Biały (anemiczny): narządy z jednym krążeniem końcowym (serce, nerki, śledziona, mózg). Klin z martwicą skrzepową. Czerwony (krwotoczny): narządy z podwójnym krążeniem (płuca, wątroba, jelita) lub po reperfuzji. Zawał mięśnia sercowego: podwsierdziowy (NSTEMI) vs pełnościenny (STEMI).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Martwica skrzepowa (koagulacyjna)', 'Najczęstszy typ martwicy. Zachowana architektura tkankowa (kontury komórek widoczne, ale jądra zanikają). Denaturacja białek strukturalnych i enzymatycznych. Lokalizacja: serce, nerki, wątroba, śledziona (narządy lite — zawał). Wyjątek: mózg — martwica rozpływna (liquefaction), nie koagulacyjna, z powodu dużej zawartości lipidów.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Martwica rozpływna (liquefaction)', 'Enzymy lizosomalne trawią tkankę → płynna masa. Typowa dla: mózgu (zawał mózgu → jama), ropni (neutrofile uwalniają enzymy). Trzustkowa martwica tłuszczowa: lipaza trzustkowa trawi tłuszcz → zmydlenie (saponifikacja — kredowobiałe ogniska). Martwica serowata: gruźlica — bezstrukturalna, serowata masa (lipidy + białka).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Apoptoza vs martwica', 'Apoptoza: programowana śmierć komórkowa. Kurczenie komórki, kondensacja chromatyny, ciałka apoptotyczne, brak zapalenia. Wewnętrzna (mitochondrialna, cytochrom c, kaspazy-9) lub zewnętrzna (Fas/FasL, TNF, kaspazy-8). Martwica: śmierć patologiczna. Obrzęk komórki, rozpad błony, uwalnianie zawartości → zapalenie. Nieprogramowana. Kaspazy wykonawcze obu szlaków: kaspaza-3.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obrzęk — podział i mechanizmy', 'Przesięk (transsudate): niskie białko (< 3 g/dl), niska LDH. Przyczyny: niewydolność serca (zastój), marskość wątroby (hipoalbuminemia, nadciśnienie wrotne), zespół nerczycowy. Wysięk (exudate): wysokie białko (> 3 g/dl), wysoka LDH. Przyczyny: zapalenie, infekcja, nowotwór. Kryteria Lighta różnicują wysięk i przesięk w płynie opłucnowym.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs — definicja i klasyfikacja', 'Wstrząs = nieadekwatna perfuzja tkankowa → hipoksja komórkowa → niewydolność narządowa. Typy: 1) Hipowolemiczny (krwotok, oparzenia, biegunka). 2) Kardiogenny (zawał, tamponada). 3) Dystrybucyjny: septyczny (wazodylatacja, przeciek kapilarny), anafilaktyczny (histamina), neurogenny (utrata tonu współczulnego). 4) Obstrukcyjny (PE, odma prężna).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs septyczny — patofizjologia', 'Infekcja → SIRS (uogólniona odpowiedź zapalna) → sepsa → wstrząs septyczny. Lipopolisacharyd (LPS, gram-) → TLR4 → TNF-α, IL-1, IL-6 → wazodylatacja systemowa (NO↑) → spadek SVR → hipotensja. Zwiększona przepuszczalność kapilar → obrzęk, hipowolemia. DIC (rozsiane wykrzepianie). Niewydolność wielonarządowa (MOF). Ciepły wstrząs → zimny wstrząs.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs — fazy', 'Faza kompensacji: tachykardia, wazokonstrykcja (współczulna), oliguria (RAAS), zachowana świadomość. Ciśnienie może być jeszcze prawidłowe. Faza dekompensacji: hipotensja, kwasica mleczanowa, splątanie, oliguria progresywna. Faza nieodwracalna: niewydolność wielonarządowa (MODS), DIC, kwasica, brak odpowiedzi na leczenie, śmierć.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu I (natychmiastowa)', 'IgE-zależna. Faza uczulenia: antygen → Th2 → IL-4 → limfocyty B → IgE → opłaszczenie mastocytów. Reekspozycja: antygen krzyżowo wiąże IgE → degranulacja mastocytów → histamina, leukotrieny, prostaglandyny. Faza wczesna (minuty): wazodylatacja, skurcz oskrzeli, obrzęk. Faza późna (6–24h): naciek eozynofilowy. Przykłady: anafilaksja, astma alergiczna, katar sienny, pokrzywka.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Anafilaksja — objawy i postępowanie', 'Systemowa reakcja typu I (IgE). Objawy: hipotensja (wazodylatacja), tachykardia, bronchospazm, obrzęk krtani, pokrzywka, świąd, wymioty. Może być śmiertelna w minutach. Leczenie: adrenalina i.m. (NATYCHMIAST — α1 wazokonstrykcja + β2 bronchodylatacja + β1 serce), płyny i.v., antyhistaminiki, kortykosteroidy, pozycja Trendelenburga.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu II (cytotoksyczna)', 'Przeciwciała IgG/IgM skierowane przeciwko antygenom na powierzchni komórek. Mechanizmy uszkodzenia: 1) Opsonizacja → fagocytoza (autoimmunologiczna anemia hemolityczna). 2) Aktywacja dopełniacza → liza (reakcja poprzetoczeniowa). 3) ADCC (zależna od przeciwciał cytotoksyczność komórkowa — NK). 4) Przeciwciała anty-receptorowe: stymulujące (Graves) lub blokujące (miastenia gravis).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu III (kompleksy immunologiczne)', 'Kompleksy antygen-przeciwciało odkładają się w tkankach → aktywacja dopełniacza → rekrutacja neutrofilów → uszkodzenie tkanki. Lokalne (reakcja Arthusa): obrzęk, martwica w miejscu wstrzyknięcia. Systemowe: choroba posurowicza (gorączka, wysypka, zapalenie stawów, kłębuszkowe zapalenie nerek). Inne: SLE (DNA + anty-DNA), zapalenie naczyń, postreptokokowe GN.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu IV (opóźniona, komórkowa)', 'Mediowana przez limfocyty T (nie przeciwciała). Rozwija się w 24–72 h. Mechanizm: antygen prezentowany przez APC → aktywacja Th1 → IFN-γ → aktywacja makrofagów → zapalenie ziarniniakowe. Lub: CD8+ (cytotoksyczne) → liza komórek. Przykłady: test tuberkulinowy (PPD), kontaktowe zapalenie skóry (nikiel, poison ivy), odrzucanie przeszczepu, choroba Hashimoto, reakcja na leki.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tolerancja immunologiczna — centralna i obwodowa', 'Centralna: eliminacja autoreaktywnych limfocytów T w grasicy (selekcja negatywna — komórki mTEC prezentują autoantigeny, gen AIRE) i B w szpiku. Obwodowa: anergia (brak sygnału kostymulującego), supresja (limfocyty Treg — FOXP3, IL-10, TGF-β), delecja (apoptoza przez Fas/FasL). Zaburzenie tolerancji → autoimmunizacja.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Toczeń rumieniowaty układowy (SLE) — patogeneza', 'Choroba autoimmunologiczna z przeciwciałami anty-dsDNA i anty-Smith (Sm). Kompleksy immunologiczne odkładają się w nerkach (nefropatia toczniowa), stawach, skórze, sercu. Typ III nadwrażliwości (głównie). Objawy: rumień motylkowaty, zapalenie stawów, nefritis, zapalenie osierdzia/opłucnej, pancytopenia. Kobiety >> mężczyźni. ANA pozytywne (~100%), ale niespecyficzne.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reumatoidalne zapalenie stawów (RZS) — patogeneza', 'Przewlekłe autoimmunologiczne zapalenie stawów. Zapalenie błony maziowej (pannus) → destrukcja chrząstki i kości. RF (czynnik reumatoidalny): IgM anty-IgG Fc — mało specyficzny. Anty-CCP (antycytrulinowe): bardziej specyficzne. Symetryczne zajęcie małych stawów rąk (PIP, MCP, nie DIP). Guzki reumatoidalne. Manifestacje pozastawowe: płuca, naczynia, serce.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Amyloidoza — definicja i typy', 'Odkładanie się nierozpuszczalnych włókien białkowych (β-harmonijka) w tkankach. AL (łańcuchy lekkie immunoglobulin): szpiczak, gammapatia monoklonalna → serce, nerki, nerwy. AA (amyloid A osocza — białko ostrej fazy): przewlekłe zapalenie (RZS, TB) → nerki, wątroba. Barwienie: czerwień Kongo → jabłkowo-zielona dwójłomność w świetle spolaryzowanym.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('DIC (rozsiane wykrzepianie wewnątrznaczyniowe)', 'Jednoczesna aktywacja krzepnięcia i fibrynolizy. Przyczyny: sepsa (LPS → TF), powikłania położnicze, nowotwory (TF, mucyny), uraz, ukąszenia węży. Klinicznie: mikrozakrzepy → niewydolność narządowa + zużycie czynników i płytek → krwawienie. Lab: PT↑, aPTT↑, fibrynogen↓, D-dimery↑, płytki↓, schistocyty w rozmazie. Leczenie: przyczynowe + płytki/FFP w aktywnym krwawieniu.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Adaptacja komórkowa — hiperplazja i hipertrofia', 'Hiperplazja: wzrost liczby komórek (wymaga zdolności do podziału). Fizjologiczna: endometrium (estrogeny), laktacja (gruczoł piersiowy). Patologiczna: łagodny przerost prostaty (BPH), endometrium (nadmiar estrogenów → ryzyko raka). Hipertrofia: wzrost rozmiaru komórek. Serce (ciśnieniowe → koncentryczna, objętościowe → ekscentryczna), mięśnie szkieletowe (trening).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Adaptacja komórkowa — zanik (atrofia)', 'Zmniejszenie rozmiaru komórek i/lub ich liczby. Przyczyny: odnerwianie (polio → zanik mięśni), niedostateczne odżywienie, utrata stymulacji hormonalnej (menopauza → zanik endometrium), zmniejszony przepływ krwi (niedokrwienie), ucisk (guz uciskający tkankę). Mechanizmy: zmniejszenie syntezy białek, wzrost proteolizy (ubikwityna-proteasom, autofagia). Lipofuscyna w zanieczych komórkach.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Uszkodzenie komórki odwracalne vs nieodwracalne', 'Odwracalne: obrzęk komórki (zaburzenie pompy Na⁺/K⁺), obrzęk ER, utrata mikrokosmków, zwyrodnienie tłuszczowe. Nieodwracalne: uszkodzenie błony komórkowej (utrata integralności), masywny napływ Ca²⁺, obrzęk mitochondriów z gęstościami amorficznymi, rozpad lizosomów → autoliza, karioliza/karioreksja/piknoza jądra. Punkt bez powrotu: uszkodzenie błon.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Uszkodzenie reperfuzyjne', 'Paradoksalnie reperfuzja po niedokrwieniu może pogorszyć uszkodzenie. Mechanizmy: 1) Wolne rodniki tlenowe (reoxygenation injury — ksantynooksydaza, neutrofile). 2) Napływ Ca²⁺ do uszkodzonych komórek. 3) Nacieki neutrofilowe (adhezja do reaktywowanego śródbłonka). 4) Aktywacja dopełniacza. Klinicznie: po angioplastyce (STEMI), po transplantacji narządu.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Miażdżyca (atherosclerosis) — patogeneza', 'Uszkodzenie śródbłonka → retencja LDL w intimie → oksydacja LDL → makrofagi fagocytują ox-LDL → komórki piankowate → pasmo tłuszczowe → migracja mięśni gładkich → blaszka włóknisto-tłuszczowa (czapeczka włóknista + rdzeń lipidowy). Pęknięcie cienkiej czapeczki → zakrzep → zawał. Czynniki ryzyka: dyslipidemia, nadciśnienie, cukrzyca, palenie, wiek, płeć męska.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemostaza — kaskada krzepnięcia (uproszczona)', 'Hemostaza pierwotna: adhezja płytek (vWF → GP1b), aktywacja (TXA2, ADP), agregacja (fibrynogen → GPIIb/IIIa). Hemostaza wtórna: kaskada krzepnięcia. Szlak zewnętrzny: TF + VII → Xa (PT/INR). Szlak wewnętrzny: XII→XI→IX→VIII→Xa (aPTT). Wspólny: Xa + Va → protrombina → trombina → fibrynogen → fibryna. XIIIa stabilizuje skrzep.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Białka antykoagulacyjne — antytrombina III, białko C i S', 'Antytrombina III (AT III): hamuje trombinę i czynniki IXa, Xa, XIa. Heparyna wzmacnia działanie AT III ~1000×. Białko C (aktywowane przez trombomodulynę → APC): inaktywuje czynniki Va i VIIIa. Białko S: kofaktor białka C. Niedobory: trombofilia → zakrzepica żylna. Czynnik V Leiden: oporność na APC — najczęstsza wrodzona trombofilia.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
